const input = $input.first().json;
const actionType = input.action_type;
const actionInput = JSON.stringify(input.action_input);

// Cache key based on tool + input
const cacheKey = `${actionType}:${actionInput}`.substring(0, 200);

// Cacheable tools (read-only operations)
const cacheableTools = ['file_read', 'grep', 'glob', 'git_status', 'sheets_read', 'gmail_list', 'clickup_list_tasks', 'n8n_list_workflows', 'meta_capabilities'];

// Check if this tool is cacheable
const isCacheable = cacheableTools.includes(actionType);

// For now, pass through - actual caching would require external storage
// This marks results as cacheable for potential future caching layer
return {
  json: {
    ...input,
    cache: {
      key: cacheKey,
      cacheable: isCacheable,
      ttl_seconds: isCacheable ? 300 : 0  // 5 min TTL for cacheable tools
    }
  }
};

// Token bucket rate limiter
const input = $input.first().json;
const sessionId = input.session_id;

// Rate limit config
const maxRequests = 20;  // Max requests per window
const windowMs = 60000;   // 1 minute window

// Get or initialize rate limit state
let rateLimitState = input.state?.rate_limit || {
  requests: 0,
  window_start: Date.now()
};

const now = Date.now();
const windowElapsed = now - rateLimitState.window_start;

// Reset window if expired
if (windowElapsed >= windowMs) {
  rateLimitState = { requests: 0, window_start: now };
}

// Check if rate limited
const isRateLimited = rateLimitState.requests >= maxRequests;

if (isRateLimited) {
  const retryAfter = Math.ceil((windowMs - windowElapsed) / 1000);
  return {
    json: {
      ...input,
      rate_limited: true,
      retry_after_seconds: retryAfter,
      message: `Rate limit exceeded. Retry after ${retryAfter} seconds.`
    }
  };
}

// Increment request count
rateLimitState.requests++;

// Update state
if (!input.state) input.state = {};
input.state.rate_limit = rateLimitState;

return {
  json: {
    ...input,
    rate_limited: false,
    requests_remaining: maxRequests - rateLimitState.requests
  }
};

// Circuit Breaker Pattern - Prevents cascade failures
const input = $input.first().json;
const now = Date.now();

// Circuit breaker state (would be persisted in production)
const circuitState = {
  failures: $env.CIRCUIT_FAILURES || 0,
  lastFailure: $env.CIRCUIT_LAST_FAILURE || 0,
  state: $env.CIRCUIT_STATE || 'closed', // closed, open, half-open
  threshold: 5,  // Open circuit after 5 failures
  timeout: 30000, // 30 seconds before trying again
  halfOpenRequests: 0,
  maxHalfOpenRequests: 3
};

// Check if circuit should transition
if (circuitState.state === 'open') {
  if (now - circuitState.lastFailure > circuitState.timeout) {
    circuitState.state = 'half-open';
    circuitState.halfOpenRequests = 0;
  } else {
    return {
      json: {
        ...input,
        circuit_breaker: {
          state: 'open',
          blocked: true,
          retry_after_ms: circuitState.timeout - (now - circuitState.lastFailure),
          message: 'Circuit breaker is OPEN - too many failures. Retry later.'
        }
      }
    };
  }
}

if (circuitState.state === 'half-open') {
  if (circuitState.halfOpenRequests >= circuitState.maxHalfOpenRequests) {
    return {
      json: {
        ...input,
        circuit_breaker: {
          state: 'half-open',
          blocked: true,
          message: 'Circuit breaker is testing - max half-open requests reached.'
        }
      }
    };
  }
  circuitState.halfOpenRequests++;
}

return {
  json: {
    ...input,
    circuit_breaker: {
      state: circuitState.state,
      blocked: false,
      failures: circuitState.failures,
      message: `Circuit ${circuitState.state} - request allowed`
    }
  }
};

// Request Validator - Validates incoming requests
const input = $input.first().json;
const body = input.body || input;

const errors = [];
const warnings = [];

// Required field validation
if (!body.task && !body.debug) {
  errors.push('Missing required field: task');
}

// Task validation
if (body.task) {
  if (typeof body.task === 'string') {
    if (body.task.length < 3) {
      errors.push('Task description too short (min 3 chars)');
    }
    if (body.task.length > 10000) {
      errors.push('Task description too long (max 10000 chars)');
    }
  } else if (typeof body.task === 'object') {
    if (!body.task.objective) {
      errors.push('Task object missing objective field');
    }
  }
}

// Config validation
if (body.config) {
  if (body.config.max_iterations && (body.config.max_iterations < 1 || body.config.max_iterations > 100)) {
    errors.push('max_iterations must be between 1 and 100');
  }
  if (body.config.timeout && body.config.timeout > 600000) {
    warnings.push('Timeout exceeds 10 minutes - may hit system limits');
  }
}

// Template validation
const validTemplates = ['coder', 'researcher', 'analyst', 'writer', 'devops', 'orchestrator'];
if (body.template && !validTemplates.includes(body.template)) {
  errors.push(`Invalid template: ${body.template}. Valid: ${validTemplates.join(', ')}`);
}

// Persona validation
const validPersonas = ['senior_engineer', 'rapid_prototyper', 'research_analyst', 'devops_specialist'];
if (body.persona && !validPersonas.includes(body.persona)) {
  errors.push(`Invalid persona: ${body.persona}. Valid: ${validPersonas.join(', ')}`);
}

// Input sanitization - remove potential injection attempts
const sanitized = { ...body };
if (sanitized.task && typeof sanitized.task === 'string') {
  // Remove dangerous patterns
  sanitized.task = sanitized.task
    .replace(/\$\(.*?\)/g, '[REMOVED_SUBSHELL]')
    .replace(/`.*?`/g, '[REMOVED_BACKTICK]')
    .replace(/\|\|/g, '[REMOVED_OR]')
    .replace(/&&/g, '[REMOVED_AND]');
}

const isValid = errors.length === 0;

return {
  json: {
    ...input,
    body: sanitized,
    validation: {
      valid: isValid,
      errors: errors,
      warnings: warnings,
      sanitized: sanitized.task !== body.task
    }
  }
};

const input = $input.first().json;

return {
  json: {
    success: false,
    error: 'VALIDATION_ERROR',
    message: 'Request validation failed',
    errors: input.validation.errors,
    warnings: input.validation.warnings,
    timestamp: new Date().toISOString()
  }
};

// Priority Queue - Assigns and manages task priority
const input = $input.first().json;
const body = input.body || input;

// Priority levels
const PRIORITY = {
  CRITICAL: 1,   // System emergencies, errors
  HIGH: 2,       // User-flagged urgent tasks
  NORMAL: 3,     // Standard requests
  LOW: 4,        // Background tasks
  BATCH: 5       // Bulk/batch operations
};

// Determine priority based on request characteristics
let priority = PRIORITY.NORMAL;
let priorityReason = 'default';

// Check for explicit priority
if (body.priority) {
  if (typeof body.priority === 'number' && body.priority >= 1 && body.priority <= 5) {
    priority = body.priority;
    priorityReason = 'explicit';
  } else if (typeof body.priority === 'string') {
    priority = PRIORITY[body.priority.toUpperCase()] || PRIORITY.NORMAL;
    priorityReason = 'explicit_string';
  }
}

// Auto-detect priority from task content
const taskText = (typeof body.task === 'string' ? body.task : body.task?.objective || '').toLowerCase();

if (taskText.includes('urgent') || taskText.includes('asap') || taskText.includes('emergency')) {
  priority = Math.min(priority, PRIORITY.HIGH);
  priorityReason = 'detected_urgent';
}

if (taskText.includes('critical') || taskText.includes('production') || taskText.includes('outage')) {
  priority = PRIORITY.CRITICAL;
  priorityReason = 'detected_critical';
}

if (body.background === true || taskText.includes('batch') || taskText.includes('bulk')) {
  priority = Math.max(priority, PRIORITY.BATCH);
  priorityReason = 'detected_batch';
}

// Calculate estimated wait time based on priority (mock)
const estimatedWaitMs = priority * 100; // Higher priority = shorter wait

return {
  json: {
    ...input,
    priority_queue: {
      priority: priority,
      priority_name: Object.keys(PRIORITY).find(k => PRIORITY[k] === priority),
      reason: priorityReason,
      estimated_wait_ms: estimatedWaitMs,
      queued_at: new Date().toISOString()
    }
  }
};

// Request Deduplication - Prevents duplicate task processing
const input = $input.first().json;
const body = input.body || input;
const crypto = require('crypto');

// Generate request fingerprint
const taskContent = typeof body.task === 'string' ? body.task : JSON.stringify(body.task);
const fingerprintData = [
  taskContent,
  body.template || '',
  body.persona || '',
  body.session_id || ''
].join('|');

const fingerprint = crypto.createHash('md5').update(fingerprintData).digest('hex');

// Check for recent duplicates (would use Redis/cache in production)
// For now, we'll generate a unique request ID
const requestId = `req_${Date.now().toString(36)}_${fingerprint.substring(0, 8)}`;

// Idempotency key from client
const idempotencyKey = body.idempotency_key || null;

return {
  json: {
    ...input,
    deduplication: {
      fingerprint: fingerprint,
      request_id: requestId,
      idempotency_key: idempotencyKey,
      is_duplicate: false, // Would check cache in production
      first_seen: new Date().toISOString()
    }
  }
};

// Graceful Degradation - Fallback when services unavailable
const input = $input.first().json;

// Check which services are available
const serviceStatus = {
  bridge_api: input.circuit_breaker?.state === 'closed',
  claude_api: true, // Assume available unless known otherwise
  gmail: true,
  sheets: true,
  sms: true
};

// Determine degradation level
let degradationLevel = 'none';
let availableFeatures = [];
let unavailableFeatures = [];

if (!serviceStatus.bridge_api) {
  degradationLevel = 'partial';
  unavailableFeatures.push('tool_execution', 'file_operations', 'command_execution');
  availableFeatures.push('conversation', 'planning');
}

// Fallback mode configuration
const fallbackConfig = {
  level: degradationLevel,
  message: degradationLevel === 'none'
    ? 'All services operational'
    : `Operating in ${degradationLevel} degradation mode`,
  available: availableFeatures,
  unavailable: unavailableFeatures,
  recommended_action: degradationLevel === 'none' ? null : 'Retry in 60 seconds'
};

return {
  json: {
    ...input,
    degradation: fallbackConfig
  }
};

// Batch Processor - Handle multiple tasks in single request
const input = $input.first().json;
const body = input.body || input;

// Check if this is a batch request
const isBatch = Array.isArray(body.tasks) && body.tasks.length > 0;

if (!isBatch) {
  // Single task - pass through
  return {
    json: {
      ...input,
      batch: {
        is_batch: false,
        task_count: 1,
        current_index: 0
      }
    }
  };
}

// Batch request - process each task
const tasks = body.tasks;
const batchId = `batch_${Date.now().toString(36)}`;

// Return all tasks as separate items for parallel processing
const items = tasks.map((task, index) => ({
  json: {
    ...input,
    body: {
      ...body,
      task: task,
      tasks: undefined // Remove tasks array
    },
    batch: {
      is_batch: true,
      batch_id: batchId,
      task_count: tasks.length,
      current_index: index,
      parallel: body.batch_parallel !== false
    }
  }
}));

return items;

// Batch Results Aggregator - Combine results from batch processing
const items = $input.all();

// Check if this was a batch request
const firstItem = items[0]?.json;
if (!firstItem?.batch?.is_batch) {
  // Single task - pass through
  return items;
}

// Aggregate batch results
const batchId = firstItem.batch.batch_id;
const results = items.map((item, index) => ({
  index: index,
  success: item.json.success !== false,
  result: item.json.result || item.json,
  error: item.json.error || null
}));

const successCount = results.filter(r => r.success).length;
const failureCount = results.filter(r => !r.success).length;

return {
  json: {
    batch_id: batchId,
    total_tasks: results.length,
    successful: successCount,
    failed: failureCount,
    success_rate: (successCount / results.length * 100).toFixed(1) + '%',
    results: results,
    completed_at: new Date().toISOString()
  }
};

// Timeout Handler - Manage request timeouts gracefully
const input = $input.first().json;

const config = input.config || {};
const startTime = input.deduplication?.first_seen || new Date().toISOString();
const elapsedMs = Date.now() - new Date(startTime).getTime();

const timeoutMs = config.timeout || 120000; // Default 2 minutes
const warningThreshold = 0.8; // Warn at 80% of timeout

const timeoutStatus = {
  elapsed_ms: elapsedMs,
  timeout_ms: timeoutMs,
  remaining_ms: Math.max(0, timeoutMs - elapsedMs),
  percent_used: ((elapsedMs / timeoutMs) * 100).toFixed(1),
  warning: elapsedMs > (timeoutMs * warningThreshold),
  expired: elapsedMs >= timeoutMs
};

if (timeoutStatus.expired) {
  return {
    json: {
      success: false,
      error: 'TIMEOUT',
      message: `Request timed out after ${timeoutMs}ms`,
      timeout_status: timeoutStatus,
      partial_result: input.result || null
    }
  };
}

return {
  json: {
    ...input,
    timeout_status: timeoutStatus
  }
};

// Prometheus-style Metrics Collector
const input = $input.first().json;

// Collect metrics from the request lifecycle
const metrics = {
  // Request metrics
  request_total: 1,
  request_duration_ms: Date.now() - new Date(input.deduplication?.first_seen || Date.now()).getTime(),
  request_size_bytes: JSON.stringify(input.task || {}).length,

  // Response metrics
  response_success: input.success !== false ? 1 : 0,
