  tool_calls_total: input.state?.cost_tracker?.tool_calls || 0,

  // Token metrics
  tokens_input: input.state?.cost_tracker?.input_tokens || 0,
  tokens_output: input.state?.cost_tracker?.output_tokens || 0,
  tokens_total: (input.state?.cost_tracker?.input_tokens || 0) + (input.state?.cost_tracker?.output_tokens || 0),

  // Cost metrics
  cost_usd: input.state?.cost_tracker?.total_cost || 0,

  // Priority metrics
  priority_level: input.priority_queue?.priority || 3,

  // Circuit breaker metrics
  circuit_state: input.circuit_breaker?.state || 'closed',
  circuit_failures: input.circuit_breaker?.failures || 0,

  // Queue metrics
  queue_wait_ms: input.priority_queue?.estimated_wait_ms || 0,

  // Labels for Prometheus
  labels: {
    template: input.template_used || 'default',
    persona: input.persona_used || 'none',
    batch: input.batch?.is_batch ? 'true' : 'false',
    priority: input.priority_queue?.priority_name || 'NORMAL'
  }
};

// Format as Prometheus exposition format
const prometheusFormat = [
  `# HELP agent_request_total Total number of requests`,
  `# TYPE agent_request_total counter`,
  `agent_request_total{template="${metrics.labels.template}",persona="${metrics.labels.persona}"} ${metrics.request_total}`,
  ``,
  `# HELP agent_request_duration_ms Request duration in milliseconds`,
  `# TYPE agent_request_duration_ms histogram`,
  `agent_request_duration_ms{template="${metrics.labels.template}"} ${metrics.request_duration_ms}`,
  ``,
  `# HELP agent_tokens_total Total tokens used`,
  `# TYPE agent_tokens_total counter`,
  `agent_tokens_total{type="input"} ${metrics.tokens_input}`,
  `agent_tokens_total{type="output"} ${metrics.tokens_output}`,
  ``,
  `# HELP agent_cost_usd Total cost in USD`,
  `# TYPE agent_cost_usd counter`,
  `agent_cost_usd ${metrics.cost_usd}`,
  ``,
  `# HELP agent_circuit_state Circuit breaker state (0=closed, 1=open, 2=half-open)`,
  `# TYPE agent_circuit_state gauge`,
  `agent_circuit_state ${metrics.circuit_state === 'closed' ? 0 : metrics.circuit_state === 'open' ? 1 : 2}`
].join('\n');

return {
  json: {
    ...input,
    metrics: metrics,
    prometheus_format: prometheusFormat
  }
};

// JWT Authentication with Role-Based Access Control
const input = $input.first().json;
const headers = input.headers || {};

// Get authorization header
const authHeader = headers.authorization || headers.Authorization || '';
const apiKey = headers['x-api-key'] || '';

// Supported auth methods
const authMethods = {
  jwt: authHeader.startsWith('Bearer '),
  apiKey: !!apiKey,
  none: !authHeader && !apiKey
};

let authResult = {
  authenticated: false,
  method: 'none',
  user: null,
  roles: [],
  permissions: []
};

// Role definitions
const ROLES = {
  admin: {
    permissions: ['*'],  // All permissions
    rate_limit: 1000,
    cost_limit: 100.0
  },
  developer: {
    permissions: ['read', 'write', 'execute', 'debug'],
    rate_limit: 100,
    cost_limit: 10.0
  },
  user: {
    permissions: ['read', 'execute'],
    rate_limit: 20,
    cost_limit: 1.0
  },
  readonly: {
    permissions: ['read'],
    rate_limit: 10,
    cost_limit: 0.1
  }
};

// API Key authentication (simple)
if (authMethods.apiKey) {
  // Known API keys (would be in database in production)
  const API_KEYS = {
    'agent-orchestrator-key': { user: 'admin', roles: ['admin'] },
    'dev-key-123': { user: 'developer', roles: ['developer'] },
    'user-key-456': { user: 'user', roles: ['user'] }
  };

  const keyData = API_KEYS[apiKey];
  if (keyData) {
    authResult = {
      authenticated: true,
      method: 'api_key',
      user: keyData.user,
      roles: keyData.roles,
      permissions: keyData.roles.flatMap(r => ROLES[r]?.permissions || []),
      rate_limit: Math.max(...keyData.roles.map(r => ROLES[r]?.rate_limit || 10)),
      cost_limit: Math.max(...keyData.roles.map(r => ROLES[r]?.cost_limit || 0.1))
    };
  }
}

// JWT authentication (simplified - would verify signature in production)
if (authMethods.jwt && !authResult.authenticated) {
  try {
    const token = authHeader.replace('Bearer ', '');
    // In production: verify JWT signature and decode
    // For now, just check if token looks valid
    const parts = token.split('.');
    if (parts.length === 3) {
      // Decode payload (base64)
      const payload = JSON.parse(Buffer.from(parts[1], 'base64').toString());
      authResult = {
        authenticated: true,
        method: 'jwt',
        user: payload.sub || payload.user || 'unknown',
        roles: payload.roles || ['user'],
        permissions: (payload.roles || ['user']).flatMap(r => ROLES[r]?.permissions || []),
        rate_limit: payload.rate_limit || 20,
        cost_limit: payload.cost_limit || 1.0,
        exp: payload.exp
      };

      // Check expiration
      if (payload.exp && Date.now() / 1000 > payload.exp) {
        authResult.authenticated = false;
        authResult.error = 'Token expired';
      }
    }
  } catch (e) {
    authResult.error = 'Invalid JWT format';
  }
}

// Default to allowing unauthenticated requests with minimal permissions
if (!authResult.authenticated && !authResult.error) {
  authResult = {
    authenticated: false,
    method: 'anonymous',
    user: 'anonymous',
    roles: ['readonly'],
    permissions: ['read', 'execute'],  // Allow basic execution for testing
    rate_limit: 5,
    cost_limit: 0.01,
    warning: 'No authentication provided - limited access'
  };
}

return {
  json: {
    ...input,
    auth: authResult
  }
};

// Role-Based Access Control Check
const input = $input.first().json;
const auth = input.auth || {};
const body = input.body || {};

// Determine required permission based on action
const actionPermissions = {
  // Read operations
  'file_read': 'read',
  'grep': 'read',
  'glob': 'read',
  'git_status': 'read',
  'gmail_list': 'read',
  'gmail_read': 'read',
  'sheets_read': 'read',

  // Write operations
  'file_write': 'write',
  'file_edit': 'write',
  'sheets_write': 'write',
  'sheets_append': 'write',

  // Execute operations
  'command': 'execute',
  'terminal_multi_command': 'execute',
  'terminal_script': 'execute',

  // Send operations (higher privilege)
  'gmail_send': 'send',
  'sms_send': 'send',

  // Admin operations
  'n8n_create_workflow': 'admin',
  'n8n_activate_workflow': 'admin',
  'meta_create_tool': 'admin'
};

// Get requested tools from agent config
const requestedTools = body.agent?.tools_available || [];
const template = body.template;

// Determine required permissions
let requiredPermissions = new Set(['execute']);  // Base permission

if (template === 'devops' || template === 'orchestrator') {
  requiredPermissions.add('admin');
}

// Check tool permissions
for (const tool of requestedTools) {
  const perm = actionPermissions[tool];
  if (perm) requiredPermissions.add(perm);
}

// Verify permissions
const userPermissions = new Set(auth.permissions || []);
const hasWildcard = userPermissions.has('*');

const missingPermissions = [];
for (const perm of requiredPermissions) {
  if (!hasWildcard && !userPermissions.has(perm)) {
    missingPermissions.push(perm);
  }
}

const authorized = missingPermissions.length === 0;

return {
  json: {
    ...input,
    rbac: {
      authorized: authorized,
      user: auth.user,
      roles: auth.roles,
      required_permissions: Array.from(requiredPermissions),
      user_permissions: Array.from(userPermissions),
      missing_permissions: missingPermissions,
      rate_limit: auth.rate_limit || 10,
      cost_limit: auth.cost_limit || 0.1
    }
  }
};

