// Budget Enforcement - Cost and Resource Limits
const input = $input.first().json;
const auth = input.auth || {};
const rbac = input.rbac || {};
const body = input.body || {};

// Get user's limits from RBAC
const costLimit = rbac.cost_limit || auth.cost_limit || 1.0;  // USD
const rateLimit = rbac.rate_limit || auth.rate_limit || 10;   // requests per minute

// Current usage (would be tracked in database in production)
const currentUsage = {
  cost_today: 0.0,  // Would query from database
  requests_this_minute: 0,  // Would query from rate limiter
  tokens_today: 0
};

// Estimate cost for this request
const estimatedTokens = 4000;  // Conservative estimate
const costPerToken = 0.00001;  // Approximate Claude cost
const estimatedCost = estimatedTokens * costPerToken;

// Check budget limits
const budgetStatus = {
  cost_limit: costLimit,
  cost_used: currentUsage.cost_today,
  cost_remaining: costLimit - currentUsage.cost_today,
  cost_estimated: estimatedCost,

  rate_limit: rateLimit,
  rate_used: currentUsage.requests_this_minute,
  rate_remaining: rateLimit - currentUsage.requests_this_minute,

  // Enforcement decisions
  within_budget: currentUsage.cost_today + estimatedCost <= costLimit,
  within_rate_limit: currentUsage.requests_this_minute < rateLimit,

  // Warnings
  budget_warning: currentUsage.cost_today > costLimit * 0.8,
  rate_warning: currentUsage.requests_this_minute > rateLimit * 0.8
};

// Block if over limits
if (!budgetStatus.within_budget) {
  return {
    json: {
      success: false,
      error: 'BUDGET_EXCEEDED',
      message: `Daily cost limit of $${costLimit} exceeded`,
      budget: budgetStatus,
      suggestion: 'Wait until tomorrow or upgrade your plan'
    }
  };
}

if (!budgetStatus.within_rate_limit) {
  return {
    json: {
      success: false,
      error: 'RATE_LIMIT_EXCEEDED',
      message: `Rate limit of ${rateLimit} requests/minute exceeded`,
      budget: budgetStatus,
      retry_after_seconds: 60,
      suggestion: 'Wait and retry, or upgrade your plan'
    }
  };
}

return {
  json: {
    ...input,
    budget: budgetStatus
  }
};

