// Request Replay Engine - Replay failed requests from audit log
const input = $input.first().json;

// Replay configuration
const REPLAY_CONFIG = {
  enabled: true,
  max_replays: 3,
  replay_delay_ms: 1000,
  eligible_errors: [
    'TIMEOUT',
    'RATE_LIMIT',
    'TEMPORARY_FAILURE',
    'CONNECTION_ERROR'
  ],
  // Errors that should never be replayed
  excluded_errors: [
    'AUTHORIZATION_FAILED',
    'INVALID_INPUT',
    'PERMISSION_DENIED',
    'BUDGET_EXCEEDED'
  ]
};

// Check if this request is a replay
const isReplay = input.replay?.is_replay || false;
const replayCount = input.replay?.count || 0;

// Determine if request is eligible for replay
const currentError = input.error?.code || input.state?.last_error?.code;
const isEligible = currentError &&
  REPLAY_CONFIG.eligible_errors.includes(currentError) &&
  !REPLAY_CONFIG.excluded_errors.includes(currentError) &&
  replayCount < REPLAY_CONFIG.max_replays;

// Build replay context
const replayContext = {
  is_replay: isReplay,
  replay_count: replayCount,
  max_replays: REPLAY_CONFIG.max_replays,

  // Current request eligibility
  current_error: currentError,
  eligible_for_replay: isEligible,

