    original_request_id: input.deduplication?.request_id,
    original_trace_id: input.trace?.trace_id,
    error_that_triggered: currentError,
    scheduled_replay_at: new Date(Date.now() + REPLAY_CONFIG.replay_delay_ms * Math.pow(2, replayCount)).toISOString(),
