  current_ms: currentDuration,
  target_ms: rtSla.target_ms,
  status: currentDuration <= rtSla.target_ms ? 'ok' :
          currentDuration <= rtSla.warning_ms ? 'warning' : 'violation',
  percent_of_target: Math.round((currentDuration / rtSla.target_ms) * 100)
};

