// Policy Engine - Declarative rules for access and actions
const input = $input.first().json;
const auth = input.auth || {};
const tenant = input.tenant || {};
const body = input.body || {};

// Policy definitions (would be loaded from config in production)
const POLICIES = {
  // Access policies
  'access.admin_only_tools': {
    description: 'Restrict dangerous tools to admins',
    condition: (ctx) => {
      const dangerousTools = ['git_push', 'git_reset_hard', 'file_delete', 'command'];
      const requestedTools = ctx.body?.agent?.tools_available || [];
      const hasAdmin = ctx.auth?.roles?.includes('admin');
      return !requestedTools.some(t => dangerousTools.includes(t)) || hasAdmin;
    },
    action: 'deny',
    message: 'Admin role required for dangerous operations'
  },

  'access.sandbox_readonly': {
    description: 'Sandbox tenants are read-only',
    condition: (ctx) => {
      if (ctx.tenant?.sandbox_mode !== true) return true;
      const writeOps = ['write', 'edit', 'create', 'delete', 'push'];
      const taskText = (typeof ctx.body?.task === 'string' ? ctx.body.task : '').toLowerCase();
      return !writeOps.some(op => taskText.includes(op));
    },
    action: 'deny',
    message: 'Sandbox tenants are read-only'
  },

  // Rate policies
  'rate.expensive_operations': {
    description: 'Limit expensive operations',
    condition: (ctx) => {
      const expensiveOps = ['analyze_codebase', 'multi_file_refactor'];
      const taskText = (typeof ctx.body?.task === 'string' ? ctx.body.task : '').toLowerCase();
      if (!expensiveOps.some(op => taskText.includes(op))) return true;
      // Check if under limit (simplified)
      return (ctx.budget?.cost_remaining || 1) > 0.5;
    },
    action: 'throttle',
    message: 'Expensive operation - checking rate limit'
  },

  // Content policies
  'content.no_secrets': {
    description: 'Prevent secrets in output',
    condition: (ctx) => {
      const taskText = (typeof ctx.body?.task === 'string' ? ctx.body.task : '').toLowerCase();
      const secretPatterns = ['api key', 'password', 'secret', 'credential', 'token'];
      return !secretPatterns.some(p => taskText.includes('show ' + p) || taskText.includes('print ' + p));
    },
    action: 'deny',
    message: 'Cannot display secrets in output'
  },

  // Time-based policies
  'time.business_hours': {
    description: 'Allow destructive ops only in business hours',
    condition: (ctx) => {
      const hour = new Date().getHours();
      const isBusinessHours = hour >= 9 && hour < 17;
      const destructiveOps = ['delete', 'drop', 'remove', 'destroy'];
      const taskText = (typeof ctx.body?.task === 'string' ? ctx.body.task : '').toLowerCase();
      if (!destructiveOps.some(op => taskText.includes(op))) return true;
      return isBusinessHours || ctx.auth?.roles?.includes('admin');
    },
    action: 'deny',
    message: 'Destructive operations only allowed during business hours (9-17)'
  }
};

// Evaluate all policies
const ctx = { auth, tenant, body, budget: input.budget };
const evaluations = [];
const violations = [];

for (const [policyId, policy] of Object.entries(POLICIES)) {
  const passed = policy.condition(ctx);
  const evaluation = {
    policy_id: policyId,
    description: policy.description,
    passed: passed,
    action: passed ? 'allow' : policy.action
  };
  evaluations.push(evaluation);

  if (!passed) {
    violations.push({
      policy_id: policyId,
      action: policy.action,
      message: policy.message
    });
  }
}

// Determine overall result
const denied = violations.filter(v => v.action === 'deny');
const throttled = violations.filter(v => v.action === 'throttle');

const policyResult = {
  allowed: denied.length === 0,
  throttled: throttled.length > 0,
  evaluations: evaluations,
  violations: violations,
  denied_by: denied.map(d => d.policy_id),
  denial_reasons: denied.map(d => d.message)
};

// If denied, return early
if (!policyResult.allowed) {
  return {
    json: {
      success: false,
      error: 'POLICY_VIOLATION',
