// Anomaly Detection - Statistical outlier detection
const input = $input.first().json;

// Baseline metrics (would be learned from historical data)
const BASELINES = {
  response_time_ms: { mean: 2000, stddev: 500 },
  tokens_per_request: { mean: 1500, stddev: 500 },
  tool_calls_per_request: { mean: 3, stddev: 2 },
  cost_per_request: { mean: 0.01, stddev: 0.005 },
  error_rate: { mean: 0.02, stddev: 0.01 }
};

// Z-score calculation
const zScore = (value, mean, stddev) => {
  if (stddev === 0) return 0;
  return (value - mean) / stddev;
};

// Current metrics
const metrics = {
  response_time_ms: input.sla?.report?.duration_ms || 0,
  tokens_per_request: (input.state?.cost_tracker?.input_tokens || 0) + (input.state?.cost_tracker?.output_tokens || 0),
  tool_calls_per_request: input.state?.cost_tracker?.tool_calls || 0,
  cost_per_request: input.state?.cost_tracker?.total_cost || 0
};

// Detect anomalies
const anomalies = [];
const scores = {};

for (const [metric, value] of Object.entries(metrics)) {
  const baseline = BASELINES[metric];
  if (!baseline) continue;

  const z = zScore(value, baseline.mean, baseline.stddev);
  scores[metric] = {
    value: value,
    baseline_mean: baseline.mean,
    baseline_stddev: baseline.stddev,
    z_score: z,
    is_anomaly: Math.abs(z) > 2  // More than 2 standard deviations
  };

  if (Math.abs(z) > 2) {
    anomalies.push({
      metric: metric,
      value: value,
      expected: baseline.mean,
      z_score: z,
      severity: Math.abs(z) > 3 ? 'critical' : 'warning',
      direction: z > 0 ? 'high' : 'low',
      message: `${metric} is ${Math.abs(z).toFixed(1)} std devs ${z > 0 ? 'above' : 'below'} normal`
    });
  }
}

// Pattern anomalies (behavioral)
const patternAnomalies = [];

// Unusual tool combination
const toolsUsed = input.state?.tools_used || [];
if (toolsUsed.includes('file_write') && toolsUsed.includes('git_push') && !toolsUsed.includes('git_add')) {
  patternAnomalies.push({
    type: 'unusual_tool_sequence',
    pattern: 'file_write -> git_push without git_add',
    severity: 'warning'
  });
}

// Rapid successive requests
if (input.correlation?.depth > 3) {
  patternAnomalies.push({
    type: 'deep_recursion',
    depth: input.correlation.depth,
    severity: 'warning'
  });
}

// Anomaly summary
const anomalyResult = {
  metrics_analyzed: Object.keys(scores).length,
  metric_anomalies: anomalies,
  pattern_anomalies: patternAnomalies,
  total_anomalies: anomalies.length + patternAnomalies.length,
  scores: scores,
  health: anomalies.length === 0 && patternAnomalies.length === 0 ? 'normal' :
          anomalies.some(a => a.severity === 'critical') ? 'critical' : 'warning'
};

return {
  json: {
    ...input,
    anomaly_detection: anomalyResult
  }
};

