// Predictive Scaling v4.6
// Uses historical patterns to predict and pre-scale resources

const SCALING_CONFIG = {
  min_instances: 1,
  max_instances: 10,
  scale_up_threshold: 0.8,  // 80% utilization
  scale_down_threshold: 0.3, // 30% utilization
  cooldown_minutes: 5,
  prediction_window_hours: 24
};

// Historical load patterns (would be populated from metrics DB)
const LOAD_PATTERNS = {
  hourly: {
    0: 0.2, 1: 0.1, 2: 0.1, 3: 0.1, 4: 0.15, 5: 0.2,
    6: 0.3, 7: 0.5, 8: 0.7, 9: 0.9, 10: 0.95, 11: 0.9,
    12: 0.85, 13: 0.9, 14: 0.95, 15: 0.9, 16: 0.85, 17: 0.8,
    18: 0.7, 19: 0.6, 20: 0.5, 21: 0.4, 22: 0.3, 23: 0.25
  },
  daily: {
    0: 0.7, 1: 0.9, 2: 1.0, 3: 1.0, 4: 0.95, 5: 0.6, 6: 0.4 // Sun-Sat
  },
  special_events: []  // Black Friday, launches, etc.
};

function predictLoad(hoursAhead = 1) {
  const now = new Date();
  const futureHour = (now.getHours() + hoursAhead) % 24;
  const futureDay = (now.getDay() + Math.floor((now.getHours() + hoursAhead) / 24)) % 7;

  const hourlyFactor = LOAD_PATTERNS.hourly[futureHour];
  const dailyFactor = LOAD_PATTERNS.daily[futureDay];

  return hourlyFactor * dailyFactor;
}

function calculateRequiredInstances(predictedLoad) {
  const baseInstances = SCALING_CONFIG.min_instances;
  const maxAdditional = SCALING_CONFIG.max_instances - baseInstances;
  const additionalNeeded = Math.ceil(predictedLoad * maxAdditional);

  return Math.min(
    SCALING_CONFIG.max_instances,
    Math.max(SCALING_CONFIG.min_instances, baseInstances + additionalNeeded)
  );
}

function generateScalingPlan() {
  const plan = [];
  for (let h = 0; h <= 24; h++) {
    const predictedLoad = predictLoad(h);
    const instances = calculateRequiredInstances(predictedLoad);
    plan.push({
      hours_ahead: h,
      predicted_load: (predictedLoad * 100).toFixed(1) + '%',
      recommended_instances: instances
    });
  }
  return plan;
}

