const CONFIG_HISTORY = [];

function updateConfig(path, value) {
  const pathParts = path.split('.');
  let current = CONFIG_STORE;

  for (let i = 0; i < pathParts.length - 1; i++) {
    current = current[pathParts[i]];
  }

  const oldValue = current[pathParts[pathParts.length - 1]];
  current[pathParts[pathParts.length - 1]] = value;

  CONFIG_STORE.version = incrementVersion(CONFIG_STORE.version);
  CONFIG_STORE.last_updated = new Date().toISOString();

  CONFIG_HISTORY.push({
    path,
    old_value: oldValue,
    new_value: value,
    timestamp: new Date().toISOString()
  });

  return { path, old_value: oldValue, new_value: value };
}

function incrementVersion(version) {
  const parts = version.split('.').map(Number);
  parts[2]++;
  return parts.join('.');
}

function getConfig(path = null) {
  if (!path) return CONFIG_STORE;

  const pathParts = path.split('.');
  let current = CONFIG_STORE;

  for (const part of pathParts) {
    current = current[part];
    if (current === undefined) return null;
  }

  return current;
}

