// Capacity Planning v4.6
// Analyzes usage trends and projects future capacity needs

const CAPACITY_METRICS = {
  current: {
    requests_per_day: 10000,
    avg_response_time_ms: 250,
    error_rate: 0.01,
    cpu_utilization: 0.65,
    memory_utilization: 0.70,
    storage_used_gb: 450,
    storage_total_gb: 1000
  },
  growth_rates: {
    requests: 0.15,  // 15% monthly growth
    storage: 0.10,   // 10% monthly growth
    users: 0.20      // 20% monthly growth
  },
  thresholds: {
    cpu_warning: 0.75,
    cpu_critical: 0.90,
    memory_warning: 0.80,
    memory_critical: 0.95,
    storage_warning: 0.80,
    storage_critical: 0.90
  }
};

function projectCapacity(months) {
  const projections = [];
  let current = { ...CAPACITY_METRICS.current };

  for (let m = 1; m <= months; m++) {
    current = {
      requests_per_day: Math.round(current.requests_per_day * (1 + CAPACITY_METRICS.growth_rates.requests)),
      cpu_utilization: Math.min(0.99, current.cpu_utilization * (1 + CAPACITY_METRICS.growth_rates.requests * 0.5)),
      memory_utilization: Math.min(0.99, current.memory_utilization * (1 + CAPACITY_METRICS.growth_rates.requests * 0.3)),
      storage_used_gb: Math.round(current.storage_used_gb * (1 + CAPACITY_METRICS.growth_rates.storage))
    };

    projections.push({
      month: m,
      ...current,
      storage_percent: (current.storage_used_gb / CAPACITY_METRICS.current.storage_total_gb * 100).toFixed(1) + '%',
      alerts: generateAlerts(current)
    });
  }

  return projections;
}

function generateAlerts(metrics) {
  const alerts = [];
  const t = CAPACITY_METRICS.thresholds;

  if (metrics.cpu_utilization >= t.cpu_critical) {
    alerts.push({ type: 'critical', resource: 'CPU', message: 'CPU will be critically overloaded' });
  } else if (metrics.cpu_utilization >= t.cpu_warning) {
    alerts.push({ type: 'warning', resource: 'CPU', message: 'CPU approaching capacity' });
  }

  if (metrics.memory_utilization >= t.memory_critical) {
    alerts.push({ type: 'critical', resource: 'Memory', message: 'Memory will be exhausted' });
  } else if (metrics.memory_utilization >= t.memory_warning) {
    alerts.push({ type: 'warning', resource: 'Memory', message: 'Memory approaching capacity' });
  }

  const storagePercent = metrics.storage_used_gb / CAPACITY_METRICS.current.storage_total_gb;
  if (storagePercent >= t.storage_critical) {
    alerts.push({ type: 'critical', resource: 'Storage', message: 'Storage will be exhausted' });
  } else if (storagePercent >= t.storage_warning) {
    alerts.push({ type: 'warning', resource: 'Storage', message: 'Storage approaching capacity' });
  }

  return alerts;
}

function generateRecommendations(projections) {
  const recommendations = [];

  // Find first month with critical alerts
  for (const p of projections) {
    const criticalAlerts = p.alerts.filter(a => a.type === 'critical');
    if (criticalAlerts.length > 0) {
      recommendations.push({
        urgency: 'high',
        timeline: `Within ${p.month} month(s)`,
        action: `Scale ${criticalAlerts.map(a => a.resource).join(', ')} resources`,
        resources: criticalAlerts.map(a => a.resource)
      });
      break;
    }
  }

  // Storage recommendation
  const storageProjection = projections[11]; // 12 month
  if (storageProjection && storageProjection.storage_used_gb > CAPACITY_METRICS.current.storage_total_gb * 0.8) {
    recommendations.push({
      urgency: 'medium',
      timeline: 'Within 6 months',
      action: 'Provision additional storage capacity',
      estimated_need_gb: Math.round(storageProjection.storage_used_gb * 1.5)
    });
  }

  return recommendations;
}

