// Idempotency Handler v4.6
// Ensures operations are safely retryable without side effects

const IDEMPOTENCY_STORE = new Map();
const IDEMPOTENCY_TTL_MS = 24 * 60 * 60 * 1000; // 24 hours

function generateIdempotencyKey(request) {
  // Create deterministic key from request content
  const keyData = {
    method: request.method || 'POST',
    path: request.path || '/execute',
    body_hash: hashContent(request.body),
    user_id: request.user_id
  };
  return 'idem_' + hashContent(JSON.stringify(keyData));
}

function hashContent(content) {
  // Simple hash for demo (use crypto in production)
  let hash = 0;
  const str = JSON.stringify(content);
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return Math.abs(hash).toString(16);
}

function checkIdempotency(key) {
  const stored = IDEMPOTENCY_STORE.get(key);
  if (!stored) return null;

  // Check if expired
  if (Date.now() - stored.timestamp > IDEMPOTENCY_TTL_MS) {
    IDEMPOTENCY_STORE.delete(key);
    return null;
  }

  return stored;
}

function storeIdempotencyResult(key, result, status) {
  IDEMPOTENCY_STORE.set(key, {
    result,
    status,
    timestamp: Date.now(),
    hit_count: 0
  });

  // Cleanup old entries
  for (const [k, v] of IDEMPOTENCY_STORE) {
    if (Date.now() - v.timestamp > IDEMPOTENCY_TTL_MS) {
      IDEMPOTENCY_STORE.delete(k);
    }
  }
}

const input = $input.all()[0]?.json || {};
const clientIdempotencyKey = input.idempotency_key;
const request = input.request || input;

// Use client-provided key or generate one
const idempotencyKey = clientIdempotencyKey || generateIdempotencyKey(request);

// Check for existing result
const existingResult = checkIdempotency(idempotencyKey);

if (existingResult) {
  existingResult.hit_count++;
  return [{
    json: {
      ...input,
      idempotency: {
        key: idempotencyKey,
        status: 'cached',
        original_timestamp: new Date(existingResult.timestamp).toISOString(),
        hit_count: existingResult.hit_count,
        cached_result: existingResult.result,
        message: 'Returning cached result for idempotent request'
      },
      skip_execution: true,
      cached_response: existingResult.result
    }
  }];
}

return [{
  json: {
    ...input,
    idempotency: {
      key: idempotencyKey,
      status: 'new',
      message: 'First time seeing this request, proceed with execution',
      store_result: true
    },
    skip_execution: false
  }
}];

// Request Shadowing v4.6
// Sends copies of requests to shadow services for testing without affecting production

const SHADOW_CONFIG = {
  enabled: true,
  shadow_percentage: 10,  // Shadow 10% of requests
  shadow_endpoints: [
    {
      name: 'staging',
      url: 'http://staging.api.internal:5011',
