      enabled: true,
      compare_responses: true
    }
  ],
  comparison_config: {
    ignore_fields: ['timestamp', 'request_id', 'latency_ms'],
    tolerance: {
      numeric: 0.01,  // 1% tolerance for numeric values
      string: 'exact'
    }
  }
};

const SHADOW_RESULTS = [];

function shouldShadow() {
  return SHADOW_CONFIG.enabled && Math.random() * 100 < SHADOW_CONFIG.shadow_percentage;
}

function compareResponses(production, shadow) {
  const differences = [];

  function compare(p, s, path = '') {
    if (typeof p !== typeof s) {
      differences.push({ path, type: 'type_mismatch', production: typeof p, shadow: typeof s });
      return;
    }

    if (typeof p === 'object' && p !== null) {
      for (const key of new Set([...Object.keys(p || {}), ...Object.keys(s || {})])) {
        if (!SHADOW_CONFIG.comparison_config.ignore_fields.includes(key)) {
          compare(p?.[key], s?.[key], path ? `${path}.${key}` : key);
        }
      }
    } else if (typeof p === 'number') {
      if (Math.abs(p - s) > Math.abs(p) * SHADOW_CONFIG.comparison_config.tolerance.numeric) {
        differences.push({ path, type: 'value_difference', production: p, shadow: s });
      }
    } else if (p !== s) {
      differences.push({ path, type: 'value_difference', production: p, shadow: s });
    }
  }

  compare(production, shadow);
  return differences;
}

function createShadowRequest(request) {
  return {
    ...request,
    headers: {
      ...request.headers,
      'X-Shadow-Request': 'true',
      'X-Shadow-Timestamp': new Date().toISOString()
    }
  };
}

const input = $input.all()[0]?.json || {};
const request = input.request || input;

const shadowDecision = shouldShadow();
const enabledShadows = SHADOW_CONFIG.shadow_endpoints.filter(e => e.enabled);

if (shadowDecision && enabledShadows.length > 0) {
  const shadowRequest = createShadowRequest(request);

  return [{
    json: {
      ...input,
      shadowing: {
        enabled: true,
        shadow_request: shadowRequest,
        shadow_targets: enabledShadows.map(e => ({
          name: e.name,
          url: e.url,
          compare: e.compare_responses
        })),
        shadow_id: 'shadow_' + Date.now(),
        message: 'Request will be shadowed to ' + enabledShadows.length + ' endpoint(s)'
      }
    }
  }];
}

return [{
  json: {
    ...input,
    shadowing: {
      enabled: false,
      reason: !SHADOW_CONFIG.enabled ? 'Shadowing disabled' : 'Not selected for shadowing (sampling)',
