const MIRROR_QUEUE = [];

function redactSensitiveData(data) {
  if (!MIRROR_CONFIG.redaction.enabled) return data;

  const redacted = JSON.parse(JSON.stringify(data));

  function redact(obj, path = '') {
    if (typeof obj !== 'object' || obj === null) return;

    for (const key of Object.keys(obj)) {
      const lowerKey = key.toLowerCase();
      if (MIRROR_CONFIG.redaction.fields.some(f => lowerKey.includes(f))) {
        obj[key] = '[REDACTED]';
      } else if (typeof obj[key] === 'object') {
        redact(obj[key], path + '.' + key);
      }
    }
  }

  redact(redacted);
  return redacted;
}

function matchesFilter(request, filter) {
  if (!filter) return true;

  for (const [key, value] of Object.entries(filter)) {
    if (request[key] !== value) return false;
  }
  return true;
}

function queueMirror(request, mirror) {
  const mirrorEntry = {
    mirror_id: 'mir_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9),
    mirror_name: mirror.name,
    destination: mirror.destination,
    type: mirror.type,
    payload: redactSensitiveData(request),
    queued_at: new Date().toISOString(),
    status: 'queued'
  };

  MIRROR_QUEUE.push(mirrorEntry);
  return mirrorEntry;
}

