  const healthyBackends = BACKENDS.filter(b => b.healthy);

  if (healthyBackends.length === 0) {
    throw new Error('No healthy backends available');
  }

  switch (algorithm) {
    case 'round_robin':
      roundRobinIndex = (roundRobinIndex + 1) % healthyBackends.length;
      return healthyBackends[roundRobinIndex];

    case 'weighted_round_robin':
      // Build weighted list
      const weightedList = [];
      for (const backend of healthyBackends) {
        for (let i = 0; i < backend.weight; i++) {
          weightedList.push(backend);
        }
      }
      roundRobinIndex = (roundRobinIndex + 1) % weightedList.length;
      return weightedList[roundRobinIndex];

    case 'least_connections':
      return healthyBackends.reduce((min, b) =>
        b.connections < min.connections ? b : min
      );

    case 'ip_hash':
      const ip = request.client_ip || '127.0.0.1';
      const hash = ip.split('.').reduce((h, oct) => h * 31 + parseInt(oct), 0);
      return healthyBackends[Math.abs(hash) % healthyBackends.length];

    default:
      return healthyBackends[0];
  }
}

function recordConnection(backendId) {
  const backend = BACKENDS.find(b => b.id === backendId);
  if (backend) backend.connections++;
}

function releaseConnection(backendId) {
  const backend = BACKENDS.find(b => b.id === backendId);
  if (backend && backend.connections > 0) backend.connections--;
}

const input = $input.all()[0]?.json || {};
const request = input.request || input;

try {
  const selectedBackend = selectBackend(LB_CONFIG.algorithm, request);
  recordConnection(selectedBackend.id);

  return [{
    json: {
      ...input,
      load_balancer: {
        selected_backend: {
