      }
    }
  }];
}

// Response Streaming v4.6
// Enables streaming responses for real-time output delivery

const STREAMING_CONFIG = {
  enabled: true,
  chunk_size_bytes: 1024,
  flush_interval_ms: 100,
  buffer_limit_bytes: 65536,
  supported_content_types: ['text/event-stream', 'application/json', 'text/plain'],
  heartbeat_interval_ms: 15000
};

const ACTIVE_STREAMS = new Map();

function createStream(requestId, config = {}) {
  const stream = {
    stream_id: 'stream_' + requestId,
    request_id: requestId,
    created_at: new Date().toISOString(),
    status: 'open',
    bytes_sent: 0,
    chunks_sent: 0,
    buffer: [],
    config: { ...STREAMING_CONFIG, ...config }
  };

  ACTIVE_STREAMS.set(stream.stream_id, stream);
  return stream;
}

function sendChunk(streamId, data) {
  const stream = ACTIVE_STREAMS.get(streamId);
  if (!stream || stream.status !== 'open') {
    return { success: false, error: 'Stream not found or closed' };
  }

  const chunk = {
    chunk_id: stream.chunks_sent + 1,
    data: data,
    timestamp: new Date().toISOString()
  };

  stream.buffer.push(chunk);
  stream.chunks_sent++;
  stream.bytes_sent += JSON.stringify(data).length;

  // Check buffer limit
  if (stream.bytes_sent > stream.config.buffer_limit_bytes) {
    stream.status = 'buffer_overflow';
    return { success: false, error: 'Buffer limit exceeded' };
  }

  return { success: true, chunk };
}

function closeStream(streamId) {
  const stream = ACTIVE_STREAMS.get(streamId);
  if (stream) {
    stream.status = 'closed';
    stream.closed_at = new Date().toISOString();
    return stream;
  }
  return null;
}

function formatSSE(data, event = 'message') {
  return `event: ${event}\ndata: ${JSON.stringify(data)}\n\n`;
}

const input = $input.all()[0]?.json || {};
const action = input.streaming_action || 'check';
const requestId = input.request_id || 'req_' + Date.now();

let result;

switch (action) {
  case 'create':
    const stream = createStream(requestId, input.stream_config);
    result = {
      action: 'create',
      stream_id: stream.stream_id,
      status: stream.status,
      config: stream.config
    };
    break;

  case 'send':
    const sendResult = sendChunk(input.stream_id, input.chunk_data);
    result = {
      action: 'send',
      ...sendResult
    };
    break;

  case 'close':
    const closedStream = closeStream(input.stream_id);
    result = {
      action: 'close',
      stream_id: input.stream_id,
      final_stats: closedStream ? {
        bytes_sent: closedStream.bytes_sent,
        chunks_sent: closedStream.chunks_sent,
        duration_ms: new Date() - new Date(closedStream.created_at)
      } : null
    };
    break;

  case 'check':
  default:
    result = {
      action: 'check',
      streaming_supported: STREAMING_CONFIG.enabled,
      active_streams: ACTIVE_STREAMS.size,
      config: {
        chunk_size: STREAMING_CONFIG.chunk_size_bytes,
        buffer_limit: STREAMING_CONFIG.buffer_limit_bytes,
        supported_types: STREAMING_CONFIG.supported_content_types
      }
    };
}

return [{
  json: {
    ...input,
    response_streaming: result
  }
}];

