    { id: 'task_2', type: 'research', status: 'running', priority: 'medium' }
  ]
};

function parseGraphQLQuery(query) {
  // Simplified GraphQL parser
  const operationMatch = query.match(/(query|mutation)\s*(\w+)?\s*\{([^}]+)\}/s);
  if (!operationMatch) return null;

  const [, operation, name, body] = operationMatch;
  const fields = body.split(/\s+/).filter(f => f && !f.includes(':'));

  return { operation, name, fields };
}

function executeQuery(parsed, variables = {}) {
  const { operation, fields } = parsed;

  if (operation === 'query') {
    // Return mock data based on requested fields
    if (fields.includes('agents') || fields.includes('agent')) {
      return { data: { agents: MOCK_DATA.agents } };
    }
    if (fields.includes('tasks') || fields.includes('task')) {
      return { data: { tasks: MOCK_DATA.tasks } };
    }
  }

  return { data: null, errors: [{ message: 'Unknown query' }] };
}

const input = $input.all()[0]?.json || {};
const query = input.graphql_query || input.query;
const variables = input.variables || {};

if (!query) {
  return [{
    json: {
      ...input,
      graphql: {
        schema: GRAPHQL_SCHEMA,
        message: 'Provide graphql_query to execute'
      }
    }
  }];
}

const parsed = parseGraphQLQuery(query);
const result = parsed ? executeQuery(parsed, variables) : { errors: [{ message: 'Parse error' }] };

return [{
  json: {
    ...input,
    graphql: {
      query,
      result,
      parsed,
      execution_time_ms: Math.floor(Math.random() * 50) + 10
    }
