  min_healthy_regions: 2
};

const FAILOVER_HISTORY = [];

function selectRegion(clientRegion, preferences = {}) {
  const healthyRegions = Object.values(REGIONS).filter(r => r.status === 'active');

  if (healthyRegions.length === 0) {
    return { error: 'No healthy regions available', fallback: 'us-east-1' };
  }

  // Prefer client's region if healthy
  if (clientRegion && REGIONS[clientRegion]?.status === 'active') {
    return REGIONS[clientRegion];
  }

  // Select by lowest latency + load
  const scored = healthyRegions.map(r => ({
    ...r,
    score: r.latency_ms + (r.load_percent * 2)
  })).sort((a, b) => a.score - b.score);

  return scored[0];
}

function initiateFailover(fromRegion, toRegion, reason) {
  const failover = {
    failover_id: `fo_${Date.now()}`,
    from_region: fromRegion,
    to_region: toRegion,
    reason,
    status: 'in_progress',
    started_at: new Date().toISOString(),
    traffic_shifted_percent: 0
  };

  FAILOVER_HISTORY.push(failover);

  // Mark source as degraded
  if (REGIONS[fromRegion]) {
    REGIONS[fromRegion].status = 'degraded';
    REGIONS[fromRegion].role = 'draining';
  }

  return failover;
}

function getGlobalStatus() {
  const healthy = Object.values(REGIONS).filter(r => r.status === 'active').length;
  const total = Object.keys(REGIONS).length;

  return {
    global_health: healthy >= FAILOVER_CONFIG.min_healthy_regions ? 'healthy' : 'degraded',
    healthy_regions: healthy,
    total_regions: total,
    primary: Object.values(REGIONS).find(r => r.role === 'primary'),
    regions: REGIONS
  };
}

