const clientRegion = input.client_region;

let result;
switch (action) {
  case 'select':
    result = selectRegion(clientRegion, input.preferences);
    break;
  case 'failover':
    result = initiateFailover(input.from_region, input.to_region, input.reason || 'manual');
    break;
  case 'history':
    result = { failovers: FAILOVER_HISTORY.slice(-10) };
    break;
  case 'status':
  default:
    result = getGlobalStatus();
}

return [{
  json: {
    ...input,
    multi_region: {
      action,
      result,
      config: FAILOVER_CONFIG
    }
  }
}];

// Adaptive Rate Limiting v4.7
// Dynamically adjusts rate limits based on system health

const RATE_LIMIT_CONFIG = {
  base_limits: {
    free: { requests_per_minute: 20, burst: 5 },
    pro: { requests_per_minute: 100, burst: 20 },
    enterprise: { requests_per_minute: 1000, burst: 100 }
  },
  adaptive: {
    enabled: true,
    health_check_interval_ms: 5000,
    adjustment_factors: {
      cpu_high: 0.5,      // Reduce to 50% when CPU > 80%
      memory_high: 0.6,   // Reduce to 60% when memory > 85%
      latency_high: 0.7,  // Reduce to 70% when latency > 2x baseline
      error_rate_high: 0.4 // Reduce to 40% when errors > 5%
    },
    recovery_rate: 0.1   // Increase by 10% per interval when healthy
  }
};

const CURRENT_HEALTH = {
  cpu_percent: 55,
  memory_percent: 70,
  avg_latency_ms: 150,
  baseline_latency_ms: 100,
  error_rate_percent: 0.5
};

const CURRENT_MULTIPLIER = { value: 1.0, reason: 'normal' };
const RATE_LIMIT_LOG = [];

function calculateMultiplier(health) {
  let multiplier = 1.0;
  let reasons = [];

  if (health.cpu_percent > 80) {
    multiplier = Math.min(multiplier, RATE_LIMIT_CONFIG.adaptive.adjustment_factors.cpu_high);
    reasons.push('cpu_high');
  }

  if (health.memory_percent > 85) {
    multiplier = Math.min(multiplier, RATE_LIMIT_CONFIG.adaptive.adjustment_factors.memory_high);
    reasons.push('memory_high');
  }

  if (health.avg_latency_ms > health.baseline_latency_ms * 2) {
    multiplier = Math.min(multiplier, RATE_LIMIT_CONFIG.adaptive.adjustment_factors.latency_high);
    reasons.push('latency_high');
  }

  if (health.error_rate_percent > 5) {
    multiplier = Math.min(multiplier, RATE_LIMIT_CONFIG.adaptive.adjustment_factors.error_rate_high);
    reasons.push('error_rate_high');
  }

  return { multiplier, reasons: reasons.length > 0 ? reasons : ['normal'] };
}

function getEffectiveLimits(tier, health = CURRENT_HEALTH) {
  const baseLimits = RATE_LIMIT_CONFIG.base_limits[tier] || RATE_LIMIT_CONFIG.base_limits.free;
  const { multiplier, reasons } = calculateMultiplier(health);

  return {
    tier,
    base_limits: baseLimits,
    effective_limits: {
      requests_per_minute: Math.floor(baseLimits.requests_per_minute * multiplier),
      burst: Math.floor(baseLimits.burst * multiplier)
    },
    multiplier,
    adjustment_reasons: reasons,
    health_snapshot: health
  };
}

function checkRateLimit(userId, tier, tokens = 1) {
  const limits = getEffectiveLimits(tier);
  // Simplified check - in production use sliding window
  const allowed = Math.random() > 0.05; // 95% pass rate for demo

  const result = {
    user_id: userId,
    allowed,
    tokens_requested: tokens,
    effective_limit: limits.effective_limits.requests_per_minute,
    multiplier: limits.multiplier,
    retry_after_ms: allowed ? null : 1000
  };

  RATE_LIMIT_LOG.push({ ...result, timestamp: new Date().toISOString() });

  return result;
}

const input = $input.all()[0]?.json || {};
const action = input.rate_limit_action || 'check';
const userId = input.user_id || 'anonymous';
const tier = input.tier || 'free';

let result;
switch (action) {
  case 'check':
    result = checkRateLimit(userId, tier, input.tokens || 1);
    break;
  case 'limits':
    result = getEffectiveLimits(tier, input.health || CURRENT_HEALTH);
    break;
  case 'health':
    result = { health: CURRENT_HEALTH, multiplier: calculateMultiplier(CURRENT_HEALTH) };
    break;
  case 'log':
    result = { log: RATE_LIMIT_LOG.slice(-50) };
    break;
  default:
    result = getEffectiveLimits(tier);
}

return [{
