// Tracks and allocates costs per tenant/team/project

const COST_RATES = {
  api_call: { unit: 'call', rate_usd: 0.0001 },
  tokens_input: { unit: '1k tokens', rate_usd: 0.003 },
  tokens_output: { unit: '1k tokens', rate_usd: 0.015 },
  compute_minute: { unit: 'minute', rate_usd: 0.01 },
  storage_gb_month: { unit: 'GB-month', rate_usd: 0.10 },
  bandwidth_gb: { unit: 'GB', rate_usd: 0.05 }
};

const TENANT_USAGE = {
  'tenant_acme': {
    tenant_id: 'tenant_acme',
    name: 'Acme Corp',
    period: '2026-02',
    usage: {
      api_calls: 15000,
      tokens_input: 2500000,
      tokens_output: 1200000,
      compute_minutes: 450,
      storage_gb: 25,
      bandwidth_gb: 100
    }
  },
  'tenant_globex': {
    tenant_id: 'tenant_globex',
    name: 'Globex Inc',
    period: '2026-02',
    usage: {
      api_calls: 8000,
      tokens_input: 1500000,
      tokens_output: 800000,
      compute_minutes: 200,
      storage_gb: 15,
      bandwidth_gb: 50
    }
  }
};

const COST_ALLOCATIONS = [];

function calculateCosts(usage) {
  const costs = {};
  let total = 0;

  costs.api_calls = (usage.api_calls || 0) * COST_RATES.api_call.rate_usd;
  costs.tokens_input = ((usage.tokens_input || 0) / 1000) * COST_RATES.tokens_input.rate_usd;
  costs.tokens_output = ((usage.tokens_output || 0) / 1000) * COST_RATES.tokens_output.rate_usd;
  costs.compute = (usage.compute_minutes || 0) * COST_RATES.compute_minute.rate_usd;
  costs.storage = (usage.storage_gb || 0) * COST_RATES.storage_gb_month.rate_usd;
  costs.bandwidth = (usage.bandwidth_gb || 0) * COST_RATES.bandwidth_gb.rate_usd;

  for (const cost of Object.values(costs)) {
    total += cost;
  }

  return { breakdown: costs, total_usd: Math.round(total * 100) / 100 };
}

function generateInvoice(tenantId, period) {
  const tenantData = TENANT_USAGE[tenantId];
  if (!tenantData) return { error: 'Tenant not found' };

  const costs = calculateCosts(tenantData.usage);

  return {
    invoice_id: `inv_${Date.now()}`,
    tenant_id: tenantId,
    tenant_name: tenantData.name,
    period,
    usage: tenantData.usage,
    costs: costs.breakdown,
    total_usd: costs.total_usd,
    generated_at: new Date().toISOString(),
    due_date: new Date(Date.now() + 30 * 86400000).toISOString().split('T')[0]
  };
}

function allocateCost(cost, allocation_rules) {
  // Allocate cost across cost centers
  const allocations = [];
  let remaining = cost;

  for (const rule of allocation_rules) {
    const allocated = cost * (rule.percent / 100);
    allocations.push({
      cost_center: rule.cost_center,
      percent: rule.percent,
      amount_usd: Math.round(allocated * 100) / 100
    });
    remaining -= allocated;
  }

  return { allocations, unallocated: Math.round(remaining * 100) / 100 };
}

