function executeRunbook(runbookId, context = {}) {
  const runbook = RUNBOOK_LIBRARY[runbookId];
  if (!runbook) return { error: 'Runbook not found' };

  const execution = {
    execution_id: `exec_${Date.now()}`,
    runbook_id: runbookId,
    runbook_name: runbook.name,
    started_at: new Date().toISOString(),
    status: 'running',
    current_step: 1,
    steps_completed: [],
    steps_pending: runbook.steps.map(s => s.id),
    context,
    requires_approval: runbook.steps.some(s => s.requires_approval)
  };

  RUNBOOK_EXECUTIONS.push(execution);
  return execution;
}

function stepResult(executionId, stepId, result) {
  const execution = RUNBOOK_EXECUTIONS.find(e => e.execution_id === executionId);
  if (!execution) return { error: 'Execution not found' };

  execution.steps_completed.push({ step_id: stepId, result, completed_at: new Date().toISOString() });
  execution.steps_pending = execution.steps_pending.filter(s => s !== stepId);
  execution.current_step++;

  if (execution.steps_pending.length === 0) {
    execution.status = 'completed';
    execution.completed_at = new Date().toISOString();
  }

  return execution;
}

