// Request Priority Queue v4.7
// Priority-based request scheduling with preemption

const PRIORITY_LEVELS = {
  CRITICAL: { level: 0, name: 'Critical', preemptive: true, max_wait_ms: 100 },
  HIGH: { level: 1, name: 'High', preemptive: true, max_wait_ms: 500 },
  NORMAL: { level: 2, name: 'Normal', preemptive: false, max_wait_ms: 5000 },
  LOW: { level: 3, name: 'Low', preemptive: false, max_wait_ms: 30000 },
  BACKGROUND: { level: 4, name: 'Background', preemptive: false, max_wait_ms: 300000 }
};

const PRIORITY_RULES = {
  'error_recovery': 'CRITICAL',
  'user_interactive': 'HIGH',
  'api_request': 'NORMAL',
  'batch_job': 'LOW',
  'analytics': 'BACKGROUND'
};

const QUEUE_STATE = {
  queues: {
    CRITICAL: [],
    HIGH: [],
    NORMAL: [],
    LOW: [],
    BACKGROUND: []
  },
  processing: [],
  max_concurrent: 10,
  stats: {
    enqueued: 0,
    dequeued: 0,
    preempted: 0
  }
};

function determinePriority(request) {
  // Check explicit priority
  if (request.priority && PRIORITY_LEVELS[request.priority]) {
    return request.priority;
  }

  // Check task type rules
  if (request.task_type && PRIORITY_RULES[request.task_type]) {
    return PRIORITY_RULES[request.task_type];
  }

  // Check user tier
  if (request.user_tier === 'enterprise') return 'HIGH';
  if (request.user_tier === 'pro') return 'NORMAL';

  return 'NORMAL';
}

function enqueue(request) {
  const priority = determinePriority(request);
  const queueItem = {
    id: `req_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
    request,
    priority,
    priority_level: PRIORITY_LEVELS[priority].level,
    enqueued_at: new Date().toISOString(),
    max_wait_ms: PRIORITY_LEVELS[priority].max_wait_ms,
    preemptive: PRIORITY_LEVELS[priority].preemptive
  };

  QUEUE_STATE.queues[priority].push(queueItem);
  QUEUE_STATE.stats.enqueued++;

  // Check if we should preempt
  if (queueItem.preemptive && QUEUE_STATE.processing.length >= QUEUE_STATE.max_concurrent) {
    const lowestPriority = QUEUE_STATE.processing
      .filter(p => p.priority_level > queueItem.priority_level)
      .sort((a, b) => b.priority_level - a.priority_level)[0];

    if (lowestPriority) {
      // Preempt lowest priority task
      QUEUE_STATE.processing = QUEUE_STATE.processing.filter(p => p.id !== lowestPriority.id);
      QUEUE_STATE.queues[lowestPriority.priority].unshift(lowestPriority);
      QUEUE_STATE.stats.preempted++;
      queueItem.preempted_task = lowestPriority.id;
    }
  }

  return queueItem;
}

function dequeue() {
  if (QUEUE_STATE.processing.length >= QUEUE_STATE.max_concurrent) {
    return { waiting: true, reason: 'Max concurrent reached' };
  }

  // Get highest priority item
  for (const priority of Object.keys(PRIORITY_LEVELS)) {
    if (QUEUE_STATE.queues[priority].length > 0) {
      const item = QUEUE_STATE.queues[priority].shift();
      item.dequeued_at = new Date().toISOString();
      item.wait_time_ms = new Date() - new Date(item.enqueued_at);
      QUEUE_STATE.processing.push(item);
      QUEUE_STATE.stats.dequeued++;
      return item;
    }
  }

  return { empty: true };
}

function complete(requestId) {
  const index = QUEUE_STATE.processing.findIndex(p => p.id === requestId);
  if (index === -1) return { error: 'Request not found in processing' };

  const item = QUEUE_STATE.processing.splice(index, 1)[0];
  item.completed_at = new Date().toISOString();
  item.processing_time_ms = new Date() - new Date(item.dequeued_at);

  return item;
}

function getQueueStats() {
  const queueLengths = {};
  for (const [priority, queue] of Object.entries(QUEUE_STATE.queues)) {
    queueLengths[priority] = queue.length;
  }

  return {
    queue_lengths: queueLengths,
    total_queued: Object.values(queueLengths).reduce((a, b) => a + b, 0),
    processing: QUEUE_STATE.processing.length,
    max_concurrent: QUEUE_STATE.max_concurrent,
    stats: QUEUE_STATE.stats
  };
}

const input = $input.all()[0]?.json || {};
const action = input.queue_action || 'status';

let result;
switch (action) {
  case 'enqueue':
    result = enqueue(input.request || {});
    break;
  case 'dequeue':
    result = dequeue();
    break;
  case 'complete':
    result = complete(input.request_id);
    break;
  case 'priority':
    result = { priority: determinePriority(input.request || {}), levels: PRIORITY_LEVELS };
    break;
  case 'status':
  default:
    result = getQueueStats();
}

return [{
  json: {
    ...input,
    priority_queue: {
      action,
      result
    }
  }
}];

