function updatePresence(workspaceId, userId, status) {
  if (!COLLABORATION_STATE.presence[workspaceId]) {
    COLLABORATION_STATE.presence[workspaceId] = {};
  }
  COLLABORATION_STATE.presence[workspaceId][userId] = {
    user_id: userId,
    status,  // 'active', 'idle', 'away'
    last_seen: new Date().toISOString(),
    cursor_position: COLLABORATION_STATE.cursors[userId] || null
  };
  return COLLABORATION_STATE.presence[workspaceId];
}

function broadcastChange(workspaceId, change) {
  const workspace = COLLABORATION_STATE.workspaces[workspaceId];
  if (!workspace) return { error: 'Workspace not found' };

  workspace.sync_version++;
  const broadcast = {
    workspace_id: workspaceId,
    change_type: change.type,
    change_data: change.data,
    author: change.author,
    sync_version: workspace.sync_version,
