// Translates natural language to API calls

const NL_PATTERNS = {
  'show.*tasks?': { endpoint: '/tasks/list', method: 'GET' },
  'list.*agents?': { endpoint: '/agents/list', method: 'GET' },
  'create.*task': { endpoint: '/tasks/create', method: 'POST', extract: ['name', 'priority'] },
  'run.*workflow': { endpoint: '/workflow/execute', method: 'POST', extract: ['workflow_id'] },
  'get.*metrics?': { endpoint: '/metrics/summary', method: 'GET' },
  'status.*system': { endpoint: '/health/dashboard', method: 'GET' },
  'find.*error': { endpoint: '/logs/search', method: 'POST', params: { level: 'error' } },
  'scale.*up': { endpoint: '/scaling/adjust', method: 'POST', params: { direction: 'up' } },
  'scale.*down': { endpoint: '/scaling/adjust', method: 'POST', params: { direction: 'down' } }
};

const ENTITY_EXTRACTORS = {
  priority: /(?:priority|urgency)[:\s]*(critical|high|medium|low)/i,
  workflow_id: /workflow[:\s]*([a-zA-Z0-9_-]+)/i,
  name: /(?:name|called|titled)[:\s]*["']?([^"']+)["']?/i,
  limit: /(?:limit|top|first)[:\s]*(\d+)/i,
  time_range: /(today|yesterday|this week|last hour)/i
};

function parseQuery(query) {
  const normalized = query.toLowerCase().trim();

  // Find matching pattern
  for (const [pattern, config] of Object.entries(NL_PATTERNS)) {
    const regex = new RegExp(pattern, 'i');
    if (regex.test(normalized)) {
      const parsed = {
        matched_pattern: pattern,
        ...config,
        extracted_entities: {},
        confidence: 0.85
      };

      // Extract entities
      if (config.extract) {
        for (const entity of config.extract) {
          const extractor = ENTITY_EXTRACTORS[entity];
          if (extractor) {
            const match = query.match(extractor);
            if (match) {
              parsed.extracted_entities[entity] = match[1];
            }
          }
        }
      }

      return parsed;
    }
  }

  return { matched_pattern: null, confidence: 0, suggestion: 'Try: show tasks, list agents, run workflow, get metrics' };
}

function translateToAPI(parsed) {
  if (!parsed.endpoint) {
    return { error: 'Could not translate query', parsed };
  }

  return {
    api_call: {
      method: parsed.method,
      endpoint: parsed.endpoint,
      params: { ...parsed.params, ...parsed.extracted_entities }
    },
    confidence: parsed.confidence,
    explanation: `Translated to ${parsed.method} ${parsed.endpoint}`
  };
}

function suggestCompletions(partial) {
  const suggestions = [
    'show all tasks',
    'list active agents',
    'create task named "Review PR" with priority high',
    'run workflow data_pipeline',
    'get system metrics',
    'find errors from last hour',
    'scale up by 2 instances'
  ];

  return suggestions.filter(s => s.toLowerCase().includes(partial.toLowerCase())).slice(0, 5);
}

