// Distributed Locking v4.8
// Coordination across multiple instances

const LOCK_STORE = {};
const LOCK_WAITERS = {};
const LOCK_HISTORY = [];

const LOCK_CONFIG = {
  default_ttl_ms: 30000,
  max_ttl_ms: 300000,
  retry_delay_ms: 100,
  max_retries: 50,
  deadlock_detection: true
};

function acquireLock(resource, owner, options = {}) {
  const ttl = Math.min(options.ttl_ms || LOCK_CONFIG.default_ttl_ms, LOCK_CONFIG.max_ttl_ms);
  const now = Date.now();

  // Check if lock exists and is valid
  const existingLock = LOCK_STORE[resource];
  if (existingLock) {
    if (existingLock.expires_at > now) {
      // Lock is held by someone else
      if (existingLock.owner === owner) {
        // Reentrant lock - extend TTL
        existingLock.expires_at = now + ttl;
        existingLock.reentry_count++;
        return { acquired: true, lock: existingLock, reentrant: true };
      }

      // Add to waiters
      if (!LOCK_WAITERS[resource]) LOCK_WAITERS[resource] = [];
      LOCK_WAITERS[resource].push({ owner, requested_at: now });

      return {
        acquired: false,
        reason: 'Lock held by another owner',
        current_owner: existingLock.owner,
        wait_position: LOCK_WAITERS[resource].length,
        retry_after_ms: Math.min(existingLock.expires_at - now, LOCK_CONFIG.retry_delay_ms)
      };
    }
    // Lock expired, clean up
    delete LOCK_STORE[resource];
  }

  // Acquire lock
  const lock = {
    resource,
    owner,
    acquired_at: new Date(now).toISOString(),
    expires_at: now + ttl,
    ttl_ms: ttl,
    reentry_count: 0
  };

  LOCK_STORE[resource] = lock;
  LOCK_HISTORY.push({ type: 'acquire', ...lock });

  return { acquired: true, lock };
}

function releaseLock(resource, owner) {
  const lock = LOCK_STORE[resource];
  if (!lock) {
    return { released: false, reason: 'Lock not found' };
  }

  if (lock.owner !== owner) {
    return { released: false, reason: 'Not lock owner' };
  }

  if (lock.reentry_count > 0) {
    lock.reentry_count--;
    return { released: false, reason: 'Reentrant lock decremented', remaining: lock.reentry_count };
  }

  delete LOCK_STORE[resource];
  LOCK_HISTORY.push({ type: 'release', resource, owner, released_at: new Date().toISOString() });

  // Notify waiters
  const waiters = LOCK_WAITERS[resource] || [];
  delete LOCK_WAITERS[resource];

  return { released: true, waiters_notified: waiters.length };
}

function extendLock(resource, owner, additionalMs) {
  const lock = LOCK_STORE[resource];
  if (!lock || lock.owner !== owner) {
    return { extended: false, reason: 'Lock not found or not owner' };
  }

  lock.expires_at += additionalMs;
  lock.ttl_ms += additionalMs;

  return { extended: true, new_expires_at: new Date(lock.expires_at).toISOString() };
}

function detectDeadlocks() {
  // Simple cycle detection in wait graph
  const waitGraph = {};
  for (const [resource, lock] of Object.entries(LOCK_STORE)) {
    const waiters = LOCK_WAITERS[resource] || [];
    for (const waiter of waiters) {
      if (!waitGraph[waiter.owner]) waitGraph[waiter.owner] = [];
      waitGraph[waiter.owner].push(lock.owner);
    }
  }

  // DFS for cycles
  const visited = new Set();
  const stack = new Set();

  function hasCycle(node) {
    if (stack.has(node)) return true;
    if (visited.has(node)) return false;
    visited.add(node);
    stack.add(node);
    for (const neighbor of (waitGraph[node] || [])) {
      if (hasCycle(neighbor)) return true;
    }
    stack.delete(node);
    return false;
  }

  for (const node of Object.keys(waitGraph)) {
    if (hasCycle(node)) {
      return { deadlock_detected: true, involved_owners: [...stack] };
    }
  }

  return { deadlock_detected: false };
}

const input = $input.all()[0]?.json || {};
const action = input.lock_action || 'status';

let result;
switch (action) {
  case 'acquire':
    result = acquireLock(input.resource, input.owner || 'default', input.options || {});
    break;
  case 'release':
    result = releaseLock(input.resource, input.owner || 'default');
    break;
  case 'extend':
    result = extendLock(input.resource, input.owner, input.extend_ms || 10000);
    break;
  case 'check':
    result = { lock: LOCK_STORE[input.resource] || null };
    break;
  case 'deadlock':
    result = detectDeadlocks();
    break;
  case 'status':
  default:
    result = {
      active_locks: Object.keys(LOCK_STORE).length,
      waiting: Object.values(LOCK_WAITERS).reduce((sum, w) => sum + w.length, 0),
      locks: Object.values(LOCK_STORE)
    };
}

return [{
  json: {
    ...input,
    distributed_locking: { action, result }
  }
}];

