    },
    migrations: {
      '1->2': { add: ['capabilities', 'status'], defaults: { capabilities: [], status: 'active' } }
    }
  }
};

const COMPATIBILITY_MATRIX = {};

function getSchema(entity, version = null) {
  const schema = SCHEMA_REGISTRY[entity];
  if (!schema) return { error: 'Schema not found' };

  const v = version || schema.current_version;
  return {
    entity,
    version: v,
    schema: schema.versions[v],
    is_current: v === schema.current_version,
    deprecated: schema.versions[v]?.deprecated_at ? new Date(schema.versions[v].deprecated_at) < new Date() : false
  };
}

function migrateData(entity, data, fromVersion, toVersion) {
  const schema = SCHEMA_REGISTRY[entity];
  if (!schema) return { error: 'Schema not found' };

  let current = { ...data };
  let currentVersion = fromVersion;

  while (currentVersion < toVersion) {
    const migrationKey = `${currentVersion}->${currentVersion + 1}`;
    const migration = schema.migrations[migrationKey];

    if (!migration) {
      return { error: `No migration path from v${currentVersion} to v${currentVersion + 1}` };
    }

    // Apply additions with defaults
    if (migration.add) {
      for (const field of migration.add) {
        if (!(field in current)) {
          current[field] = migration.defaults?.[field] ?? null;
        }
      }
    }

    // Apply removals
    if (migration.remove) {
      for (const field of migration.remove) {
        delete current[field];
      }
    }

    currentVersion++;
  }

  return {
    original_version: fromVersion,
    target_version: toVersion,
    migrated_data: current,
    migrations_applied: toVersion - fromVersion
  };
}

function checkCompatibility(entity, data, targetVersion) {
  const schema = getSchema(entity, targetVersion);
  if (schema.error) return schema;

  const issues = [];
  const fields = schema.schema.fields;

  for (const [field, type] of Object.entries(fields)) {
    if (!(field in data)) {
      issues.push({ field, issue: 'missing', severity: 'error' });
    } else if (type.startsWith('enum:')) {
      const allowedValues = type.replace('enum:', '').split(',');
      if (!allowedValues.includes(data[field])) {
        issues.push({ field, issue: 'invalid_enum', allowed: allowedValues, got: data[field], severity: 'error' });
      }
    }
  }

  // Check for extra fields
  for (const field of Object.keys(data)) {
    if (!(field in fields)) {
      issues.push({ field, issue: 'unknown_field', severity: 'warning' });
    }
  }

  return {
    compatible: issues.filter(i => i.severity === 'error').length === 0,
    issues
  };
}

const input = $input.all()[0]?.json || {};
const action = input.schema_action || 'list';

let result;
switch (action) {
  case 'get':
    result = getSchema(input.entity, input.version);
    break;
  case 'migrate':
    result = migrateData(input.entity, input.data || {}, input.from_version || 1, input.to_version || SCHEMA_REGISTRY[input.entity]?.current_version);
    break;
  case 'check':
    result = checkCompatibility(input.entity, input.data || {}, input.version);
    break;
  case 'list':
  default:
