// Request Replay Debugger v4.8
// Time-travel debugging with request replay

const REQUEST_LOG = [];
const REPLAY_SESSIONS = {};
const BREAKPOINTS = {};
const MAX_LOG_SIZE = 10000;

function recordRequest(request, response, metadata = {}) {
  const entry = {
    id: 'req_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9),
    timestamp: new Date().toISOString(),
    request: {
      method: request.method,
      path: request.path,
      headers: request.headers,
      body: request.body
    },
    response: {
      status: response.status,
      body: response.body,
      duration_ms: response.duration_ms
    },
    metadata: {
      user_id: metadata.user_id,
      session_id: metadata.session_id,
      trace_id: metadata.trace_id
    }
  };

  REQUEST_LOG.push(entry);
  if (REQUEST_LOG.length > MAX_LOG_SIZE) {
    REQUEST_LOG.shift();
  }

  return entry;
}

function createReplaySession(filter = {}) {
  const sessionId = 'replay_' + Date.now();
  let requests = [...REQUEST_LOG];

  // Apply filters
  if (filter.path) {
    requests = requests.filter(r => r.request.path.includes(filter.path));
  }
  if (filter.status) {
    requests = requests.filter(r => r.response.status === filter.status);
  }
  if (filter.after) {
    requests = requests.filter(r => new Date(r.timestamp) > new Date(filter.after));
  }
  if (filter.before) {
    requests = requests.filter(r => new Date(r.timestamp) < new Date(filter.before));
  }

  REPLAY_SESSIONS[sessionId] = {
    id: sessionId,
    requests: requests.slice(0, 100),  // Limit replay size
    current_index: 0,
    status: 'ready',
    created_at: new Date().toISOString(),
    breakpoints: [],
    modifications: {}
  };

  return REPLAY_SESSIONS[sessionId];
}

function stepReplay(sessionId, action = 'next') {
  const session = REPLAY_SESSIONS[sessionId];
  if (!session) return { error: 'Session not found' };

  switch (action) {
    case 'next':
      if (session.current_index >= session.requests.length) {
        session.status = 'completed';
        return { status: 'completed', message: 'Replay finished' };
      }
      const request = session.requests[session.current_index];
      session.current_index++;

      // Check breakpoints
      for (const bp of session.breakpoints) {
        if (request.request.path.includes(bp.path)) {
          session.status = 'paused';
          return { status: 'paused', breakpoint: bp, request };
        }
      }

      return { status: 'stepped', current: session.current_index, request };

    case 'run':
      session.status = 'running';
      const results = [];
      while (session.current_index < session.requests.length) {
        results.push(session.requests[session.current_index]);
        session.current_index++;
      }
      session.status = 'completed';
      return { status: 'completed', replayed: results.length };

    case 'reset':
      session.current_index = 0;
      session.status = 'ready';
      return { status: 'reset' };

    default:
      return { error: 'Unknown action' };
  }
}

function setBreakpoint(sessionId, condition) {
  const session = REPLAY_SESSIONS[sessionId];
  if (!session) return { error: 'Session not found' };

  const bp = {
    id: 'bp_' + Date.now(),
    ...condition
  };
  session.breakpoints.push(bp);
  return { breakpoint: bp };
}

function inspectRequest(requestId) {
  const request = REQUEST_LOG.find(r => r.id === requestId);
  if (!request) return { error: 'Request not found' };

  return {
    request,
    related: REQUEST_LOG.filter(r =>
      r.metadata.session_id === request.metadata.session_id &&
      r.id !== requestId
    ).slice(0, 10)
  };
}

const input = $input.all()[0]?.json || {};
const action = input.debug_action || 'status';

let result;
switch (action) {
  case 'record':
    result = recordRequest(input.request || {}, input.response || {}, input.metadata || {});
    break;
  case 'create_session':
    result = createReplaySession(input.filter || {});
    break;
  case 'step':
    result = stepReplay(input.session_id, input.step_action || 'next');
    break;
  case 'breakpoint':
    result = setBreakpoint(input.session_id, input.condition || {});
    break;
  case 'inspect':
    result = inspectRequest(input.request_id);
    break;
  case 'search':
    result = { requests: REQUEST_LOG.filter(r => r.request.path.includes(input.query || '')).slice(-50) };
    break;
  case 'status':
  default:
    result = {
      log_size: REQUEST_LOG.length,
      active_sessions: Object.keys(REPLAY_SESSIONS).length,
      recent_requests: REQUEST_LOG.slice(-5)
    };
}

return [{
