  },
  model_selector: {
    name: 'Model Selector',
    features: ['task_type', 'complexity', 'budget'],
    output: 'recommended_model'
  }
};

const ROUTING_HISTORY = [];
const BACKEND_STATS = {
  'claude-opus': { avg_latency: 2500, success_rate: 0.99, capacity: 0.6 },
  'claude-sonnet': { avg_latency: 1200, success_rate: 0.995, capacity: 0.4 },
  'claude-haiku': { avg_latency: 400, success_rate: 0.998, capacity: 0.2 }
};

function classifyComplexity(request) {
  let score = 0;

  // Token estimation
  const textLength = JSON.stringify(request).length;
  score += Math.min(textLength / 10000, 0.4);

  // Tool usage
  const toolCount = (request.tools || []).length;
  score += Math.min(toolCount / 10, 0.3);

  // Nesting depth (simplified)
  const nestingDepth = (JSON.stringify(request).match(/\{/g) || []).length;
  score += Math.min(nestingDepth / 20, 0.3);

  return Math.min(score, 1);
}

function predictLatency(request, backend) {
  const stats = BACKEND_STATS[backend];
  const complexity = classifyComplexity(request);

  // Base latency + complexity factor
  const baseLatency = stats.avg_latency;
  const complexityMultiplier = 1 + (complexity * 2);  // Up to 3x for complex

  // Time of day factor (simulated)
  const hour = new Date().getHours();
  const peakFactor = (hour >= 9 && hour <= 17) ? 1.2 : 1.0;

  return Math.round(baseLatency * complexityMultiplier * peakFactor);
}

function selectOptimalBackend(request, constraints = {}) {
  const complexity = classifyComplexity(request);
  const candidates = [];

  for (const [backend, stats] of Object.entries(BACKEND_STATS)) {
    const predictedLatency = predictLatency(request, backend);

    // Check constraints
    if (constraints.max_latency && predictedLatency > constraints.max_latency) {
      continue;
    }
    if (constraints.min_quality && complexity > 0.7 && backend === 'claude-haiku') {
      continue;  // Skip haiku for complex tasks
    }

    candidates.push({
      backend,
      predicted_latency: predictedLatency,
      capacity: stats.capacity,
      success_rate: stats.success_rate,
      score: (1 / predictedLatency) * stats.success_rate * (1 - stats.capacity)  // Balance speed, reliability, load
    });
  }

  candidates.sort((a, b) => b.score - a.score);

  const selected = candidates[0] || { backend: 'claude-sonnet', reason: 'fallback' };

  ROUTING_HISTORY.push({
    timestamp: new Date().toISOString(),
    complexity,
    selected_backend: selected.backend,
    alternatives: candidates.length
  });

  return {
    selected: selected.backend,
    complexity,
    predicted_latency: selected.predicted_latency,
    confidence: selected.score ? 0.85 : 0.5,
    alternatives: candidates.slice(1).map(c => c.backend)
  };
}

function learnFromOutcome(routingId, actualLatency, success) {
  // Would update model weights in production
  return {
    recorded: true,
    feedback: { actual_latency: actualLatency, success },
    model_updated: true
  };
}

const input = $input.all()[0]?.json || {};
const action = input.router_action || 'route';

let result;
switch (action) {
  case 'route':
    result = selectOptimalBackend(input.request || {}, input.constraints || {});
    break;
  case 'complexity':
    result = { complexity: classifyComplexity(input.request || {}), scale: '0-1' };
    break;
  case 'predict':
    result = {
      predictions: Object.keys(BACKEND_STATS).map(b => ({
        backend: b,
        predicted_latency: predictLatency(input.request || {}, b)
      }))
    };
    break;
  case 'feedback':
    result = learnFromOutcome(input.routing_id, input.actual_latency, input.success);
    break;
  case 'stats':
    result = { backends: BACKEND_STATS, history: ROUTING_HISTORY.slice(-20) };
    break;
  default:
    result = { models: Object.keys(ROUTING_MODELS) };
}

return [{
