    intelligent_router: { action, result }
  }
}];

// Dependency Injection Container v4.8
// Runtime service composition and lifecycle management

const SERVICE_REGISTRY = {};
const SCOPE_INSTANCES = {};
const LIFECYCLE_HOOKS = { onInit: [], onDestroy: [] };

const SCOPES = {
  SINGLETON: 'singleton',  // One instance for all
  TRANSIENT: 'transient',  // New instance each time
  SCOPED: 'scoped'         // One instance per scope/request
};

function registerService(name, config) {
  SERVICE_REGISTRY[name] = {
    name,
    factory: config.factory,
    dependencies: config.dependencies || [],
    scope: config.scope || SCOPES.SINGLETON,
    instance: null,
    initialized: false,
    metadata: config.metadata || {}
  };

  return { registered: true, service: name, scope: config.scope };
}

function resolveService(name, scopeId = 'default') {
  const service = SERVICE_REGISTRY[name];
  if (!service) {
    return { error: `Service '${name}' not registered` };
  }

  // Check for circular dependencies
  const resolving = new Set();
  function detectCircular(svcName) {
    if (resolving.has(svcName)) {
      return true;
    }
    resolving.add(svcName);
    const svc = SERVICE_REGISTRY[svcName];
    if (svc) {
      for (const dep of svc.dependencies) {
        if (detectCircular(dep)) return true;
      }
    }
    resolving.delete(svcName);
    return false;
  }

  if (detectCircular(name)) {
    return { error: 'Circular dependency detected', service: name };
  }

  // Return existing instance for singleton
  if (service.scope === SCOPES.SINGLETON && service.instance) {
    return { instance: service.instance, cached: true };
  }

  // Check scoped instance
  if (service.scope === SCOPES.SCOPED) {
    if (!SCOPE_INSTANCES[scopeId]) SCOPE_INSTANCES[scopeId] = {};
    if (SCOPE_INSTANCES[scopeId][name]) {
      return { instance: SCOPE_INSTANCES[scopeId][name], cached: true };
    }
  }

  // Resolve dependencies first
  const resolvedDeps = {};
  for (const depName of service.dependencies) {
    const depResult = resolveService(depName, scopeId);
    if (depResult.error) return depResult;
    resolvedDeps[depName] = depResult.instance;
  }

  // Create instance
  const instance = service.factory(resolvedDeps);

  // Store based on scope
  if (service.scope === SCOPES.SINGLETON) {
    service.instance = instance;
    service.initialized = true;
  } else if (service.scope === SCOPES.SCOPED) {
    SCOPE_INSTANCES[scopeId][name] = instance;
  }

  // Run init hooks
  for (const hook of LIFECYCLE_HOOKS.onInit) {
    hook(name, instance);
  }

  return { instance, cached: false, scope: service.scope };
}

function disposeScope(scopeId) {
  const instances = SCOPE_INSTANCES[scopeId] || {};

  for (const [name, instance] of Object.entries(instances)) {
    for (const hook of LIFECYCLE_HOOKS.onDestroy) {
      hook(name, instance);
    }
  }

  delete SCOPE_INSTANCES[scopeId];
  return { disposed: true, services: Object.keys(instances).length };
}

function getServiceGraph() {
  const nodes = [];
  const edges = [];

  for (const [name, service] of Object.entries(SERVICE_REGISTRY)) {
    nodes.push({ id: name, scope: service.scope, initialized: service.initialized });
    for (const dep of service.dependencies) {
      edges.push({ from: name, to: dep });
    }
  }

  return { nodes, edges };
}

// Pre-register some mock services
registerService('logger', { factory: () => ({ log: () => {} }), scope: SCOPES.SINGLETON });
registerService('config', { factory: () => ({ get: () => 'value' }), scope: SCOPES.SINGLETON });
registerService('httpClient', { factory: (deps) => ({ fetch: () => {} }), dependencies: ['logger', 'config'], scope: SCOPES.TRANSIENT });

const input = $input.all()[0]?.json || {};
const action = input.di_action || 'list';

let result;
switch (action) {
  case 'register':
    result = registerService(input.service_name, input.config || {});
    break;
  case 'resolve':
    result = resolveService(input.service_name, input.scope_id);
    break;
  case 'dispose':
    result = disposeScope(input.scope_id);
    break;
  case 'graph':
    result = getServiceGraph();
    break;
  case 'list':
  default:
    result = {
      services: Object.entries(SERVICE_REGISTRY).map(([k, v]) => ({
        name: k,
        scope: v.scope,
        dependencies: v.dependencies,
        initialized: v.initialized
      }))
    };
}

return [{
