    ...input,
    di_container: { action, result }
  }
}];

// Configuration Drift Detector v4.8
// Detect configuration divergence across environments

const BASELINE_CONFIG = {
  api: {
    rate_limit: 100,
    timeout_ms: 30000,
    retries: 3,
    endpoints: ['v1', 'v2']
  },
  features: {
    caching: true,
    streaming: true,
    batch_processing: true
  },
  security: {
    auth_required: true,
    encryption: 'AES-256',
    token_expiry_hours: 24
  }
};

const ENVIRONMENT_CONFIGS = {
  production: {
    api: { rate_limit: 100, timeout_ms: 30000, retries: 3, endpoints: ['v1', 'v2'] },
    features: { caching: true, streaming: true, batch_processing: true },
    security: { auth_required: true, encryption: 'AES-256', token_expiry_hours: 24 }
  },
  staging: {
    api: { rate_limit: 50, timeout_ms: 60000, retries: 5, endpoints: ['v1', 'v2', 'v3-beta'] },
    features: { caching: true, streaming: true, batch_processing: false },
    security: { auth_required: true, encryption: 'AES-256', token_expiry_hours: 48 }
  },
  development: {
    api: { rate_limit: 1000, timeout_ms: 120000, retries: 0, endpoints: ['v1', 'v2', 'v3-beta'] },
    features: { caching: false, streaming: true, batch_processing: false },
    security: { auth_required: false, encryption: 'none', token_expiry_hours: 168 }
  }
};

const DRIFT_HISTORY = [];

function detectDrift(env1Config, env2Config, path = '') {
  const drifts = [];

  function compare(obj1, obj2, currentPath) {
    const allKeys = new Set([...Object.keys(obj1 || {}), ...Object.keys(obj2 || {})]);

    for (const key of allKeys) {
      const keyPath = currentPath ? `${currentPath}.${key}` : key;
      const val1 = obj1?.[key];
      const val2 = obj2?.[key];

      if (val1 === undefined) {
        drifts.push({ path: keyPath, type: 'missing_in_baseline', env_value: val2 });
      } else if (val2 === undefined) {
        drifts.push({ path: keyPath, type: 'missing_in_target', baseline_value: val1 });
      } else if (typeof val1 !== typeof val2) {
        drifts.push({ path: keyPath, type: 'type_mismatch', baseline: typeof val1, target: typeof val2 });
      } else if (typeof val1 === 'object' && !Array.isArray(val1)) {
        compare(val1, val2, keyPath);
      } else if (JSON.stringify(val1) !== JSON.stringify(val2)) {
        drifts.push({ path: keyPath, type: 'value_mismatch', baseline: val1, target: val2 });
      }
    }
  }

  compare(env1Config, env2Config, path);
  return drifts;
}

function analyzeAllEnvironments() {
  const results = {};

  for (const [envName, envConfig] of Object.entries(ENVIRONMENT_CONFIGS)) {
    const drifts = detectDrift(BASELINE_CONFIG, envConfig);
    results[envName] = {
      drift_count: drifts.length,
      drifts,
      severity: drifts.length > 5 ? 'high' : drifts.length > 2 ? 'medium' : 'low'
    };
  }

  return results;
}

function suggestRemediation(drift) {
  switch (drift.type) {
    case 'missing_in_target':
      return { action: 'add', path: drift.path, value: drift.baseline_value };
    case 'missing_in_baseline':
      return { action: 'review', path: drift.path, note: 'New config in target, consider adding to baseline' };
    case 'value_mismatch':
      return { action: 'update', path: drift.path, from: drift.target, to: drift.baseline };
    case 'type_mismatch':
      return { action: 'fix_type', path: drift.path, expected: drift.baseline };
    default:
      return { action: 'investigate', path: drift.path };
  }
}

function recordDriftCheck() {
  const analysis = analyzeAllEnvironments();
  DRIFT_HISTORY.push({
    timestamp: new Date().toISOString(),
    summary: Object.entries(analysis).map(([env, data]) => ({ env, drift_count: data.drift_count, severity: data.severity }))
  });
  return analysis;
}

const input = $input.all()[0]?.json || {};
const action = input.drift_action || 'check';

let result;
switch (action) {
  case 'check':
    result = recordDriftCheck();
    break;
  case 'compare':
    const env1 = ENVIRONMENT_CONFIGS[input.env1] || BASELINE_CONFIG;
    const env2 = ENVIRONMENT_CONFIGS[input.env2] || {};
    result = { drifts: detectDrift(env1, env2), env1: input.env1, env2: input.env2 };
    break;
  case 'remediate':
    const drifts = detectDrift(BASELINE_CONFIG, ENVIRONMENT_CONFIGS[input.environment] || {});
    result = { remediations: drifts.map(d => ({ drift: d, remediation: suggestRemediation(d) })) };
    break;
  case 'baseline':
    result = { baseline: BASELINE_CONFIG };
    break;
  case 'history':
    result = { history: DRIFT_HISTORY.slice(-20) };
    break;
  default:
    result = { environments: Object.keys(ENVIRONMENT_CONFIGS) };
}

return [{
  json: {
    ...input,
    drift_detector: { action, result }
  }
}];

// Self-Healing Network v4.8
// Automatic connection recovery and circuit management

const NETWORK_STATE = {
  connections: {},
  circuits: {},
  health_checks: {},
  recovery_attempts: []
};

const HEALING_STRATEGIES = {
  connection_refused: {
    actions: ['wait_and_retry', 'switch_endpoint', 'escalate'],
    retry_delays: [1000, 2000, 5000, 10000, 30000]
  },
  timeout: {
    actions: ['increase_timeout', 'switch_region', 'cache_fallback'],
    retry_delays: [2000, 5000, 10000]
  },
  dns_failure: {
    actions: ['clear_dns_cache', 'use_ip_directly', 'escalate'],
    retry_delays: [1000, 3000]
  },
  ssl_error: {
    actions: ['refresh_certs', 'escalate'],
    retry_delays: [5000]
  },
  rate_limited: {
    actions: ['exponential_backoff', 'switch_api_key', 'queue'],
    retry_delays: [1000, 2000, 4000, 8000, 16000]
  }
};

function registerConnection(name, config) {
  NETWORK_STATE.connections[name] = {
    name,
    endpoint: config.endpoint,
    status: 'healthy',
    last_check: new Date().toISOString(),
    failure_count: 0,
    recovery_count: 0,
    circuit: 'closed',  // closed, open, half-open
    config
  };
  return NETWORK_STATE.connections[name];
}

function reportFailure(connectionName, error) {
  const conn = NETWORK_STATE.connections[connectionName];
  if (!conn) return { error: 'Connection not registered' };

  conn.failure_count++;
  conn.status = 'degraded';
  conn.last_error = error;
  conn.last_check = new Date().toISOString();

  // Circuit breaker logic
  if (conn.failure_count >= 5) {
    conn.circuit = 'open';
    conn.circuit_opens_at = new Date().toISOString();
    conn.circuit_closes_at = new Date(Date.now() + 30000).toISOString();
  }

  // Initiate healing
  const healing = initiateHealing(connectionName, error);

  return { connection: conn, healing };
}

function initiateHealing(connectionName, error) {
  const conn = NETWORK_STATE.connections[connectionName];
  const errorType = classifyError(error);
  const strategy = HEALING_STRATEGIES[errorType] || HEALING_STRATEGIES.connection_refused;

  const attempt = {
    id: 'heal_' + Date.now(),
    connection: connectionName,
    error_type: errorType,
    strategy: strategy.actions[0],
    retry_delay: strategy.retry_delays[Math.min(conn.failure_count - 1, strategy.retry_delays.length - 1)],
    started_at: new Date().toISOString(),
    status: 'pending'
  };

  NETWORK_STATE.recovery_attempts.push(attempt);

  return attempt;
}

function classifyError(error) {
  const errorStr = (error.message || error.code || String(error)).toLowerCase();

  if (errorStr.includes('econnrefused') || errorStr.includes('connection refused')) {
    return 'connection_refused';
  }
  if (errorStr.includes('timeout') || errorStr.includes('etimedout')) {
    return 'timeout';
  }
  if (errorStr.includes('dns') || errorStr.includes('enotfound')) {
    return 'dns_failure';
  }
  if (errorStr.includes('ssl') || errorStr.includes('certificate')) {
    return 'ssl_error';
  }
  if (errorStr.includes('rate') || errorStr.includes('429')) {
    return 'rate_limited';
  }

  return 'connection_refused';  // Default
}

function reportRecovery(connectionName) {
  const conn = NETWORK_STATE.connections[connectionName];
  if (!conn) return { error: 'Connection not registered' };

  conn.failure_count = 0;
  conn.status = 'healthy';
  conn.circuit = 'closed';
  conn.recovery_count++;
  conn.last_check = new Date().toISOString();

  return { connection: conn, recovered: true };
}

function getNetworkHealth() {
  const connections = Object.values(NETWORK_STATE.connections);
  const healthy = connections.filter(c => c.status === 'healthy').length;
  const degraded = connections.filter(c => c.status === 'degraded').length;
  const openCircuits = connections.filter(c => c.circuit === 'open').length;

  return {
    total_connections: connections.length,
    healthy,
    degraded,
    open_circuits: openCircuits,
    overall_health: degraded === 0 ? 'healthy' : openCircuits > 0 ? 'critical' : 'degraded',
    recent_recoveries: NETWORK_STATE.recovery_attempts.filter(r => r.status === 'completed').length
  };
}

// Pre-register some connections
registerConnection('api-primary', { endpoint: 'https://api.example.com' });
registerConnection('api-backup', { endpoint: 'https://api-backup.example.com' });
registerConnection('cache', { endpoint: 'redis://cache.internal:6379' });

