const action = input.network_action || 'health';

let result;
switch (action) {
  case 'register':
    result = registerConnection(input.connection_name, input.config || {});
    break;
  case 'failure':
    result = reportFailure(input.connection_name, input.error || {});
    break;
  case 'recovery':
    result = reportRecovery(input.connection_name);
    break;
  case 'connections':
    result = { connections: Object.values(NETWORK_STATE.connections) };
    break;
  case 'attempts':
    result = { recovery_attempts: NETWORK_STATE.recovery_attempts.slice(-20) };
    break;
  case 'health':
  default:
    result = getNetworkHealth();
}

